BEGIN;

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A proton (mass 1.67 × 10⁻²⁷ kg) moves with a speed of 5 × 10⁶ m/s perpendicular to a magnetic field of 0.5 T. The radius of the circular path described by the proton is (charge of proton = 1.6 × 10⁻¹⁹ C):", "explanation": "When a charged particle moves perpendicular to a magnetic field, it follows a circular path. The radius is given by r = mv/(qB). Substituting: r = (1.67 × 10⁻²⁷ × 5 × 10⁶) / (1.6 × 10⁻¹⁹ × 0.5) = (8.35 × 10⁻²¹) / (8.0 × 10⁻²⁰) = 0.104 m ≈ 0.1 m.", "correct_answer": "B", "concept_tags": ["circular-motion", "radius-of-path", "proton", "magnetic-field"], "payload": {"question_id": "cuet-phy-mag-force-15", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "0.01 m", "is_correct": false}, {"key": "B", "text": "0.1 m", "is_correct": true}, {"key": "C", "text": "1.0 m", "is_correct": false}, {"key": "D", "text": "0.05 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Re-check the calculation: r = mv/(qB) = (1.67 × 10⁻²⁷ × 5 × 10⁶)/(1.6 × 10⁻¹⁹ × 0.5) ≈ 0.1 m.", "misconception": "Arithmetic error in power-of-ten calculation"}, {"option_key": "C", "hint": "1.0 m is ten times the correct answer. Ensure proper handling of exponents in the numerator and denominator.", "misconception": "Arithmetic error in power-of-ten calculation"}, {"option_key": "D", "hint": "0.05 m results from an incorrect factor of 2. The formula r = mv/(qB) does not include any additional numerical factor.", "misconception": "Introducing an extraneous factor in the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The force per unit length between two long parallel conductors carrying currents I₁ and I₂ separated by a distance d is given by:", "explanation": "The magnetic field produced by conductor 1 at the location of conductor 2 is B₁ = μ₀I₁/(2πd). The force per unit length on conductor 2 is F/L = B₁I₂ = μ₀I₁I₂/(2πd). This expression is fundamental and is used to define the SI unit of current (ampere).", "correct_answer": "B", "concept_tags": ["force-per-unit-length", "parallel-conductors", "ampere-definition"], "payload": {"question_id": "cuet-phy-mag-force-16", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀I₁I₂/(4πd)", "is_correct": false}, {"key": "B", "text": "μ₀I₁I₂/(2πd)", "is_correct": true}, {"key": "C", "text": "μ₀I₁I₂/(2πd²)", "is_correct": false}, {"key": "D", "text": "μ₀I₁I₂d/(2π)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The factor is 2π in the denominator, not 4π. The field of a long wire is B = μ₀I/(2πd), and force/length = BI₂ = μ₀I₁I₂/(2πd).", "misconception": "Confusing 2π (Biot-Savart for infinite wire) with 4π (Coulomb''s law constant)"}, {"option_key": "C", "hint": "The distance d appears to the first power, not squared. This is not an inverse-square law like Coulomb''s law.", "misconception": "Incorrectly applying inverse-square law to magnetic force between wires"}, {"option_key": "D", "hint": "Having d in the numerator would mean force increases with distance, which is physically incorrect. Force decreases as conductors are moved apart.", "misconception": "Placing d in the wrong part of the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An alpha particle (charge 2e, mass 4mₚ) and a proton (charge e, mass mₚ) are accelerated from rest through the same potential difference and then enter a uniform magnetic field perpendicular to their velocity. The ratio of the radii of their circular paths (rα/rₚ) is:", "explanation": "After acceleration through potential difference V, kinetic energy K = qV. So Kα = 2eV and Kₚ = eV. The radius of circular motion is r = √(2mK)/(qB). For alpha particle: rα = √(2 × 4mₚ × 2eV)/(2eB) = √(16mₚeV)/(2eB) = 4√(mₚeV)/(2eB). For proton: rₚ = √(2mₚeV)/(eB) = √(2mₚeV)/(eB). Therefore rα/rₚ = [4√(mₚeV)/(2eB)] / [√(2mₚeV)/(eB)] = [4/(2)] × [1/√2] = 2/√2 = √2 = 1:1 × √2. So rα/rₚ = √2.", "correct_answer": "C", "concept_tags": ["alpha-particle", "proton", "radius-ratio", "potential-difference", "circular-motion"], "payload": {"question_id": "cuet-phy-mag-force-17", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "1:1", "is_correct": false}, {"key": "B", "text": "2:1", "is_correct": false}, {"key": "C", "text": "√2 : 1", "is_correct": true}, {"key": "D", "text": "1 : √2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1:1 would require identical r values. Since the alpha particle has different mass and charge, r = √(2mK)/(qB) with K = qV gives different radii.", "misconception": "Assuming equal radii for particles accelerated through same potential"}, {"option_key": "B", "hint": "2:1 would result from r ∝ m/q without properly accounting for the velocity gained through the potential difference.", "misconception": "Not correctly relating kinetic energy to the potential difference for different charges"}, {"option_key": "D", "hint": "1:√2 is the inverse of the correct ratio. The alpha particle, with greater momentum, has the larger radius.", "misconception": "Inverting the ratio of radii"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A proton and an alpha particle (charge 2e, mass 4mₚ) enter a uniform magnetic field perpendicular to their velocities. If both have the same kinetic energy, the ratio of the radii of their circular paths (rₚ/rα) is:", "explanation": "The radius of circular motion is r = mv/(qB). Since KE = ½mv², we get v = √(2KE/m), so r = m√(2KE/m)/(qB) = √(2mKE)/(qB). For the proton: rₚ = √(2mₚKE)/(eB). For the alpha particle: rα = √(2 × 4mₚ × KE)/(2eB) = 2√(2mₚKE)/(2eB) = √(2mₚKE)/(eB). Therefore rₚ/rα = [√(2mₚKE)/(eB)] / [√(2mₚKE)/(eB)] = 1. The ratio is 1:1.", "correct_answer": "D", "concept_tags": ["radius-ratio", "kinetic-energy", "proton-alpha-comparison"], "payload": {"question_id": "cuet-phy-mag-force-18", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 : 2", "is_correct": false}, {"key": "B", "text": "2 : 1", "is_correct": false}, {"key": "C", "text": "1 : √2", "is_correct": false}, {"key": "D", "text": "1 : 1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This would be correct if both had the same momentum, not the same kinetic energy. With equal KE, r = √(2mKE)/(qB).", "misconception": "Confusing equal kinetic energy with equal momentum"}, {"option_key": "B", "hint": "This is the inverse of option A. Neither is correct for equal kinetic energy conditions.", "misconception": "Inverting the ratio while still using the momentum formula"}, {"option_key": "C", "hint": "This would arise from an error in the mass or charge ratio. For an alpha particle, m = 4mₚ and q = 2e; √(4mₚ)/(2e) = √(mₚ)/e.", "misconception": "Algebraic error in evaluating √m/q for the alpha particle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A charged particle enters a region where a uniform magnetic field B and a uniform electric field E are both present and mutually perpendicular. If the particle has charge q, mass m, and enters with velocity v = E/B perpendicular to both fields, but the electric field is suddenly switched off, the radius of the resulting circular path is:", "explanation": "Initially the particle moves undeflected with v = E/B (velocity selector condition). When the electric field is switched off, only the magnetic force acts. The particle moves in a circle with radius r = mv/(qB). Substituting v = E/B: r = m(E/B)/(qB) = mE/(qB²). This radius depends on the mass-to-charge ratio and the fields.", "correct_answer": "D", "concept_tags": ["velocity-selector", "circular-motion", "radius-formula"], "payload": {"question_id": "cuet-phy-mag-force-19", "subtopic": "velocity selector", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "mE/(qB)", "is_correct": false}, {"key": "B", "text": "mB/(qE)", "is_correct": false}, {"key": "C", "text": "mE²/(qB²)", "is_correct": false}, {"key": "D", "text": "mE/(qB²)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Check dimensions: mE/(qB) has units of kg·(V/m)/(C·T) = kg·m/s² × s/(C) which is not length. You need r = mv/(qB) with v = E/B.", "misconception": "Forgetting to substitute v = E/B into the radius formula"}, {"option_key": "B", "hint": "This inverts E and B. The velocity is E/B, not B/E, so the radius involves E in the numerator and B² in the denominator.", "misconception": "Inverting the velocity selector relation"}, {"option_key": "C", "hint": "The radius is r = mv/(qB) = m(E/B)/(qB) = mE/(qB²). There is no E² term.", "misconception": "Squaring E instead of B in the substitution"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire of length L is bent into a semicircular loop and carries a current I. It is placed in a uniform magnetic field B directed perpendicular to the plane of the loop. The net force on the semicircular wire is:", "explanation": "For a curved wire in a uniform magnetic field, the net force equals the force on a straight wire connecting the two ends of the curve. The semicircular wire of length L has radius r = L/π. The straight-line distance between the two ends (the diameter) is 2r = 2L/π. Therefore, the net force is F = BI × (2L/π) = 2BIL/π. The direction follows from F = IL × B for the equivalent straight conductor.", "correct_answer": "A", "concept_tags": ["semicircular-loop", "net-force", "uniform-field", "equivalent-straight-wire"], "payload": {"question_id": "cuet-phy-mag-force-20", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "2BIL/π", "is_correct": true}, {"key": "B", "text": "BIL", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "πBIL", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "BIL would be the force if the entire wire length L were straight and perpendicular to B. But for a semicircle, the effective length is the chord (diameter) = 2L/π.", "misconception": "Using the arc length instead of the chord length for net force"}, {"option_key": "C", "hint": "Zero net force applies to a complete closed loop in a uniform field. A semicircle is not a closed loop, so the net force is not zero.", "misconception": "Confusing semicircular wire with a complete loop"}, {"option_key": "D", "hint": "πBIL greatly overestimates the force. The effective straight-line length is 2L/π, which is shorter than L, not longer.", "misconception": "Using an incorrect geometric relationship"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows a straight current-carrying conductor placed in a uniform magnetic field directed into the page. The current flows from left to right. Using Fleming''s left-hand rule, the force on the conductor is directed:", "explanation": "Using Fleming''s left-hand rule: the forefinger points in the direction of the magnetic field (into the page), the middle finger points in the direction of current (left to right). The thumb then points upward, indicating the force on the conductor is directed upward.", "correct_answer": "B", "concept_tags": ["flemings-left-hand-rule", "force-direction", "conductor-in-field"], "payload": {"question_id": "cuet-phy-mag-force-21", "subtopic": "force on current-carrying conductor (F=BIL sinθ)", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Downward", "is_correct": false}, {"key": "B", "text": "Upward", "is_correct": true}, {"key": "C", "text": "Into the page", "is_correct": false}, {"key": "D", "text": "Out of the page", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Downward would result if the current direction were reversed (right to left). Re-apply Fleming''s left-hand rule with correct current direction.", "misconception": "Reversing the current direction in Fleming''s rule"}, {"option_key": "C", "hint": "The force cannot be along the magnetic field direction. F = IL × B is perpendicular to both I and B.", "misconception": "Confusing force direction with field direction"}, {"option_key": "D", "hint": "The magnetic field is into the page. The force must be perpendicular to both B and I, which means it must be in the plane of the page (up or down).", "misconception": "Confusing the force direction with the field''s opposite direction"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a rectangular current loop ABCD placed in a uniform magnetic field B directed along the positive x-axis. The loop carries current I in the anticlockwise direction as seen from above. The plane of the loop is in the xz-plane. The net force on the loop is:", "explanation": "In a uniform magnetic field, the net force on any closed current loop is always zero. This is because the forces on opposite sides of the loop are equal in magnitude but opposite in direction. Sides AB and CD carry current parallel and antiparallel to B respectively, so the force on each is zero (sinθ = 0). Sides BC and DA are perpendicular to B and carry currents in opposite directions, so their forces cancel. The net force is zero, though a net torque may exist.", "correct_answer": "C", "concept_tags": ["current-loop", "uniform-field", "net-force-zero", "torque"], "payload": {"question_id": "cuet-phy-mag-force-22", "subtopic": "force on current-carrying conductor (F=BIL sinθ)", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "BIL along the positive y-axis", "is_correct": false}, {"key": "B", "text": "2BIL along the positive z-axis", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "BIL along the negative x-axis", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Individual sides may experience forces, but in a uniform field, forces on opposite sides cancel exactly. The net force on a closed loop in a uniform field is always zero.", "misconception": "Summing magnitudes of forces without considering directions"}, {"option_key": "B", "hint": "Forces on sides BC and DA are equal and opposite, so they cancel. The net force is zero in a uniform field.", "misconception": "Forgetting that opposite sides carry current in opposite directions relative to B"}, {"option_key": "D", "hint": "No net translational force exists on a closed loop in a uniform field. A net force requires a non-uniform field.", "misconception": "Confusing net force with net torque on the loop"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows two long parallel wires P and Q separated by distance d, carrying currents I₁ and I₂ respectively in the same direction (upward). The force on wire Q due to wire P is:", "explanation": "Wire P produces a magnetic field at the location of Q. Using the right-hand rule, the field due to P at Q''s location points into the page (for P on the left carrying current upward). Wire Q carries current upward in this field (into the page), so by F = IL × B, the force on Q is directed toward P (attractive). The magnitude is F/L = μ₀I₁I₂/(2πd). Parallel currents in the same direction always attract.", "correct_answer": "A", "concept_tags": ["parallel-currents", "attractive-force", "right-hand-rule", "force-direction"], "payload": {"question_id": "cuet-phy-mag-force-23", "subtopic": "force between parallel currents", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Attractive, directed toward wire P, with magnitude μ₀I₁I₂/(2πd) per unit length", "is_correct": true}, {"key": "B", "text": "Repulsive, directed away from wire P, with magnitude μ₀I₁I₂/(2πd) per unit length", "is_correct": false}, {"key": "C", "text": "Attractive, directed toward wire P, with magnitude μ₀I₁I₂/(4πd) per unit length", "is_correct": false}, {"key": "D", "text": "Zero, because the fields from the two wires cancel", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Same-direction currents attract, not repel. Opposite-direction currents repel. This is a fundamental result.", "misconception": "Reversing the attraction/repulsion rule for parallel currents"}, {"option_key": "C", "hint": "The formula uses 2π in the denominator, not 4π. F/L = μ₀I₁I₂/(2πd) is the standard result.", "misconception": "Confusing the 2π factor with 4π from Biot-Savart law"}, {"option_key": "D", "hint": "Each wire experiences a force due to the other wire''s field. The fields do not cancel at the wire locations.", "misconception": "Confusing field superposition at a midpoint with force on a wire"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The diagram shows a charged particle of charge +q entering a region with both electric field E (upward) and magnetic field B (into the page) with velocity v directed to the right. For what value of v will the particle travel in a straight line, and what happens if the speed is doubled?", "explanation": "For straight-line motion, the electric force qE (upward) must balance the magnetic force qvB (downward, by Fleming''s left-hand rule for a positive charge moving right in a field into the page). So qE = qvB, giving v = E/B. If the speed is doubled to 2E/B, the magnetic force becomes 2qE (downward) while the electric force remains qE (upward). The net force is qE downward, and the particle curves downward.", "correct_answer": "D", "concept_tags": ["velocity-selector", "crossed-fields", "force-balance", "deflection"], "payload": {"question_id": "cuet-phy-mag-force-24", "subtopic": "velocity selector", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "v = E/B; if doubled, the particle curves upward", "is_correct": false}, {"key": "B", "text": "v = B/E; if doubled, the particle curves downward", "is_correct": false}, {"key": "C", "text": "v = E/B; if doubled, the particle continues in a straight line", "is_correct": false}, {"key": "D", "text": "v = E/B; if doubled, the particle curves downward", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "When v > E/B, the magnetic force (downward) exceeds the electric force (upward), so the net force is downward, not upward.", "misconception": "Reversing the direction of net force when magnetic force dominates"}, {"option_key": "B", "hint": "The balance condition is v = E/B, not B/E. From qE = qvB, solving for v gives E/B.", "misconception": "Inverting the velocity selector formula"}, {"option_key": "C", "hint": "Straight-line motion requires exact balance qE = qvB. Doubling v breaks this balance, so the particle must curve.", "misconception": "Thinking the particle remains undeflected at all speeds"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The work done by a magnetic force on a charged particle moving in a magnetic field is always zero.\n\nReason (R): The magnetic force on a moving charged particle is always perpendicular to its velocity.", "explanation": "Both A and R are true, and R is the correct explanation of A. The magnetic force F = qv × B is always perpendicular to the velocity v (since the cross product is perpendicular to both vectors). Work is defined as W = F · ds, where ds is along the velocity. Since F is perpendicular to v (and hence to ds), the dot product F · ds = 0 at every instant. Therefore the magnetic force does zero work. R directly explains why A is true.", "correct_answer": "A", "concept_tags": ["work-by-magnetic-force", "perpendicular-force", "lorentz-force"], "payload": {"question_id": "cuet-phy-mag-force-25", "subtopic": "Lorentz force", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A: work = F · ds = 0 precisely because F ⊥ v. The perpendicularity is the reason for zero work.", "misconception": "Failing to connect perpendicularity of force with zero work done"}, {"option_key": "C", "hint": "R is correct. The cross product v × B is always perpendicular to v by the definition of the cross product.", "misconception": "Thinking the magnetic force can have a component along velocity"}, {"option_key": "D", "hint": "A is correct. Since F ⊥ v always, W = ∫F · ds = 0. The magnetic force cannot change the kinetic energy of a particle.", "misconception": "Thinking magnetic force can do work on a charged particle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The kinetic energy of a charged particle moving in a uniform magnetic field remains constant.\nReason (R): The magnetic force on a moving charge is always perpendicular to its velocity.", "explanation": "The assertion is correct: since the magnetic force does no work, the kinetic energy (and hence the speed) of the charged particle remains unchanged. The reason is also correct: F = qv × B is always perpendicular to v by the nature of the cross product. Furthermore, the reason correctly explains the assertion — it is precisely because the force is perpendicular to velocity that no work is done (W = F · ds = 0 when F ⊥ v), and therefore kinetic energy is conserved.", "correct_answer": "A", "concept_tags": ["kinetic-energy", "magnetic-force", "no-work", "perpendicular-force"], "payload": {"question_id": "cuet-phy-mag-force-26", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A. The perpendicularity of F to v means W = F · v dt = 0, so KE is constant. The causal link is direct.", "misconception": "Failing to see the direct causal connection between perpendicular force and zero work"}, {"option_key": "C", "hint": "The reason is a fundamental property of the cross product (v × B is always perpendicular to v). R is definitely correct.", "misconception": "Doubting the perpendicularity of the magnetic force to velocity"}, {"option_key": "D", "hint": "The assertion is correct — speed and hence KE of a charged particle in a magnetic field do not change. This is experimentally verified.", "misconception": "Thinking magnetic field changes the kinetic energy of a charge"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): A charged particle moving parallel to a magnetic field experiences no magnetic force and continues in a straight line.\n\nReason (R): The magnetic force on a charged particle is given by F = qE, where E is the electric field.", "explanation": "Assertion A is true: when a charged particle moves parallel (or antiparallel) to B, the angle θ between v and B is 0° (or 180°), so F = qvB sinθ = 0. The particle experiences no deflection and moves in a straight line. Reason R is false: the magnetic force on a moving charge is F = qv × B (Lorentz force), not F = qE. The expression F = qE describes the electric force, not the magnetic force.", "correct_answer": "C", "concept_tags": ["parallel-motion", "zero-force", "lorentz-force", "electric-vs-magnetic"], "payload": {"question_id": "cuet-phy-mag-force-27", "subtopic": "Lorentz force", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": true}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R states an incorrect formula. The magnetic force is F = qv × B, not F = qE. F = qE is the electric force.", "misconception": "Confusing the electric force formula with the magnetic force formula"}, {"option_key": "B", "hint": "R is factually incorrect as it gives the electric force formula instead of the magnetic force formula.", "misconception": "Accepting an incorrect formula as true"}, {"option_key": "D", "hint": "A is correct: when v is parallel to B, sinθ = 0 in F = qvBsinθ, so F = 0 and the particle is undeflected.", "misconception": "Thinking a charged particle always experiences force in a magnetic field"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): A current-carrying closed loop placed in a uniform magnetic field experiences a net force of zero.\nReason (R): The force on a current-carrying conductor in a magnetic field is given by F = I(L × B), where L is the length vector of the conductor.", "explanation": "The assertion is correct: for a closed loop in a uniform magnetic field, the net force is the vector sum of forces on all elements, which equals I(∮dL) × B = I × 0 × B = 0, since the line integral of dL around a closed loop is zero. The reason is also correct: F = I(L × B) is indeed the expression for force on a straight current-carrying conductor. However, the reason by itself does not directly explain why the net force on a closed loop is zero — one also needs the fact that ∮dL = 0 for a closed loop in a uniform field. So R is not the complete explanation of A.", "correct_answer": "B", "concept_tags": ["closed-loop", "net-force-zero", "uniform-field", "force-on-conductor"], "payload": {"question_id": "cuet-phy-mag-force-28", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are correct, R only gives the force formula for a conductor. It does not explain why the sum of all such forces on a closed loop is zero. The explanation requires ∮dL = 0.", "misconception": "Assuming the force formula alone explains the zero net force on a closed loop"}, {"option_key": "C", "hint": "R is indeed correct. F = I(L × B) is the standard expression for force on a current-carrying conductor in a uniform field.", "misconception": "Doubting the validity of the force formula"}, {"option_key": "D", "hint": "A is correct. A closed current loop in a uniform magnetic field has zero net force (though it may experience a torque).", "misconception": "Confusing torque with net force on a loop"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Charged particle moving parallel to B\n(Q) Charged particle moving perpendicular to B\n(R) Charged particle moving at angle θ (0° < θ < 90°) to B\n(S) Charged particle at rest in B\n\nColumn II:\n(1) Helical path\n(2) Circular path\n(3) Straight line (no force)\n(4) No motion", "explanation": "P → 3: When velocity is parallel to B, sinθ = 0, so F = 0 and the particle continues in a straight line. Q → 2: When velocity is perpendicular to B, the constant perpendicular force causes circular motion. R → 1: When velocity has both parallel and perpendicular components to B, the perpendicular component causes circular motion while the parallel component causes linear drift, resulting in a helical path. S → 4: A stationary charge (v = 0) experiences no magnetic force and remains at rest.", "correct_answer": "D", "concept_tags": ["motion-in-magnetic-field", "circular-motion", "helical-motion", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-force-29", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→2, Q→3, R→1, S→4", "is_correct": false}, {"key": "B", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "C", "text": "P→4, Q→2, R→1, S→3", "is_correct": false}, {"key": "D", "text": "P→3, Q→2, R→1, S→4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "P→2 is wrong. A particle moving parallel to B experiences zero force and moves in a straight line, not a circle.", "misconception": "Confusing parallel and perpendicular motion in B"}, {"option_key": "B", "hint": "Q→1 is wrong. A particle moving perpendicular to B traces a circle, not a helix. A helix requires a velocity component along B.", "misconception": "Confusing circular and helical paths"}, {"option_key": "C", "hint": "P→4 is wrong. A particle moving parallel to B is not stationary — it continues in a straight line since there is no magnetic force.", "misconception": "Thinking no force means no motion"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) SI unit of magnetic field\n(Q) Force between two parallel conductors carrying 1 A each, separated by 1 m, per unit length\n(R) Radius of circular path of charge q, mass m, speed v in field B\n(S) Condition for a charged particle to pass undeflected through crossed E and B fields\n\nColumn II:\n(1) mv/(qB)\n(2) 2 × 10⁻⁷ N/m\n(3) v = E/B\n(4) Tesla (T)", "explanation": "P → 4: The SI unit of magnetic field is Tesla (T). Q → 2: Using F/L = μ₀I₁I₂/(2πd) with I₁ = I₂ = 1 A, d = 1 m: F/L = (4π × 10⁻⁷ × 1 × 1)/(2π × 1) = 2 × 10⁻⁷ N/m. This is the basis for the definition of the ampere. R → 1: The radius of circular motion is r = mv/(qB), obtained by equating qvB = mv²/r. S → 3: In a velocity selector, qE = qvB gives v = E/B.", "correct_answer": "C", "concept_tags": ["tesla", "ampere-definition", "radius-formula", "velocity-selector", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-force-30", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→4, Q→1, R→2, S→3", "is_correct": false}, {"key": "B", "text": "P→4, Q→2, R→3, S→1", "is_correct": false}, {"key": "C", "text": "P→4, Q→2, R→1, S→3", "is_correct": true}, {"key": "D", "text": "P→2, Q→4, R→1, S→3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q→1 is wrong. The force per unit length between two wires is a numerical value (2 × 10⁻⁷ N/m), not the expression mv/(qB) which gives the radius of circular motion.", "misconception": "Mixing up the radius formula with the force between parallel conductors"}, {"option_key": "B", "hint": "R→3 is wrong. The radius of circular path is r = mv/(qB), not v = E/B. The condition v = E/B applies to velocity selectors.", "misconception": "Confusing the radius formula with the velocity selector condition"}, {"option_key": "D", "hint": "P→2 is wrong. The SI unit of magnetic field is Tesla (4), not 2 × 10⁻⁷ N/m (which is the force per unit length between parallel conductors).", "misconception": "Confusing the unit of B with the force value used in defining the ampere"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "When a charged particle enters a uniform magnetic field at an angle θ (where 0° < θ < 90°) to the field direction, it follows a helical path with its axis along the magnetic field direction.", "explanation": "This statement is TRUE. When a charged particle enters a magnetic field at an angle θ to B, its velocity has two components: v‖ = vcosθ (along B) and v⊥ = vsinθ (perpendicular to B). The perpendicular component causes circular motion, while the parallel component causes uniform linear motion along B. The combination of circular motion perpendicular to B and linear motion along B produces a helical (spiral) path with its axis along B.", "correct_answer": "A", "concept_tags": ["helical-motion", "velocity-components", "angle-entry"], "payload": {"question_id": "cuet-phy-mag-force-31", "subtopic": "helical motion", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The velocity component along B is unaffected by the magnetic force (F = qv × B has no component along B). This component causes forward drift while the perpendicular component causes circular motion, resulting in a helix.", "misconception": "Thinking the particle follows a circular path even when it has a velocity component along B"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The direction of force on a current-carrying conductor placed in a magnetic field can be determined using Fleming''s left-hand rule.", "explanation": "This statement is TRUE. Fleming''s left-hand rule states: if the forefinger points in the direction of the magnetic field (B), the middle finger points in the direction of current (I), then the thumb gives the direction of force (F) on the conductor. This rule is specifically used for determining the direction of force on a current-carrying conductor in a magnetic field (motor rule).", "correct_answer": "A", "concept_tags": ["flemings-left-hand-rule", "direction-of-force", "current-carrying-conductor"], "payload": {"question_id": "cuet-phy-mag-force-32", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Fleming''s left-hand rule is the standard rule for finding the direction of force on a current-carrying conductor in a magnetic field. It is widely used and correct.", "misconception": "Confusing Fleming''s left-hand rule (motor rule) with Fleming''s right-hand rule (generator/dynamo rule)"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The force between two parallel wires carrying currents in opposite directions is attractive.", "explanation": "This statement is FALSE. When two parallel wires carry currents in opposite directions, the force between them is repulsive, not attractive. Using the right-hand rule and F = IL × B, the magnetic field produced by one wire at the location of the other wire creates a force that pushes the wires apart. The rule is: same-direction currents attract, opposite-direction currents repel.", "correct_answer": "B", "concept_tags": ["parallel-currents", "repulsive-force", "opposite-currents"], "payload": {"question_id": "cuet-phy-mag-force-33", "subtopic": "force between parallel currents", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Apply the right-hand rule: the field from one wire at the other wire''s location, combined with the opposite current direction, gives a repulsive force. Same-direction currents attract; opposite-direction currents repel.", "misconception": "Confusing the rule for same and opposite direction currents"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A magnetic field can change the speed of a charged particle moving through it.", "explanation": "This statement is FALSE. The magnetic force on a charged particle is F = qv × B, which is always perpendicular to the velocity. A perpendicular force changes only the direction of velocity, not its magnitude (speed). Since no work is done by the magnetic force (W = F · ds = 0 when F ⊥ ds), the kinetic energy and hence the speed remain constant.", "correct_answer": "B", "concept_tags": ["magnetic-force", "speed-constant", "no-work", "perpendicular-force"], "payload": {"question_id": "cuet-phy-mag-force-34", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The magnetic force is always perpendicular to velocity and does zero work. Since work-energy theorem gives ΔKE = W = 0, speed cannot change.", "misconception": "Assuming any force acting on a particle changes its speed"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b09');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "A proton (mass = 1.67 × 10⁻²⁷ kg, charge = 1.6 × 10⁻¹⁹ C) moves in a circular path of radius 0.1 m in a magnetic field of 0.5 T. The speed of the proton is approximately ________ m/s.", "explanation": "For circular motion in a magnetic field: qvB = mv²/r, giving v = qBr/m. Substituting: v = (1.6 × 10⁻¹⁹ × 0.5 × 0.1)/(1.67 × 10⁻²⁷) = (8 × 10⁻²¹)/(1.67 × 10⁻²⁷) = 4.79 × 10⁶ ≈ 4.8 × 10⁶ m/s.", "correct_answer": "D", "concept_tags": ["circular-motion", "proton-speed", "radius-formula"], "payload": {"question_id": "cuet-phy-mag-force-35", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "4.8 × 10⁴", "is_correct": false}, {"key": "B", "text": "4.8 × 10⁵", "is_correct": false}, {"key": "C", "text": "4.8 × 10⁷", "is_correct": false}, {"key": "D", "text": "4.8 × 10⁶", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Check your powers of 10: (10⁻¹⁹ × 10⁻¹)/(10⁻²⁷) = 10⁻²⁰⁺²⁷ = 10⁷, not 10⁴.", "misconception": "Error in handling powers of 10"}, {"option_key": "B", "hint": "The exponent should be 6, not 5. Recount: 10⁻¹⁹ × 10⁻¹ = 10⁻²⁰; dividing by 10⁻²⁷ gives 10⁷; the coefficient 8/1.67 ≈ 4.8 adjusts this to ~4.8 × 10⁶.", "misconception": "Off-by-one error in exponent arithmetic"}, {"option_key": "C", "hint": "This would make the proton travel at nearly 1/6 the speed of light for a 0.5 T field and 0.1 m radius, which is too fast. Check the coefficient calculation.", "misconception": "Incorrect division of the numerical coefficient"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "One ampere is defined as that steady current which, when flowing through each of two infinitely long, straight, parallel conductors placed 1 m apart in vacuum, produces a force per unit length of _____ N/m between them.", "explanation": "The SI definition of one ampere is based on the force between two parallel current-carrying conductors. Using F/L = μ₀I₁I₂/(2πd), with I₁ = I₂ = 1 A and d = 1 m: F/L = (4π × 10⁻⁷ × 1 × 1)/(2π × 1) = 2 × 10⁻⁷ N/m. This value defines the ampere in the SI system.", "correct_answer": "D", "concept_tags": ["ampere-definition", "parallel-conductors", "force-per-unit-length", "SI-units"], "payload": {"question_id": "cuet-phy-mag-force-36", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "4π × 10⁻⁷", "is_correct": false}, {"key": "B", "text": "1 × 10⁻⁷", "is_correct": false}, {"key": "C", "text": "4 × 10⁻⁷", "is_correct": false}, {"key": "D", "text": "2 × 10⁻⁷", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4π × 10⁻⁷ is the value of μ₀ (permeability of free space), not the force per unit length. F/L = μ₀I₁I₂/(2πd) = μ₀/(2π) = 2 × 10⁻⁷ N/m.", "misconception": "Confusing μ₀ with the force per unit length"}, {"option_key": "B", "hint": "1 × 10⁻⁷ is half the correct value. The calculation gives μ₀/(2π) = 4π × 10⁻⁷/(2π) = 2 × 10⁻⁷, not 1 × 10⁻⁷.", "misconception": "Arithmetic error in simplifying μ₀/(2π)"}, {"option_key": "C", "hint": "4 × 10⁻⁷ is twice the correct value. Carefully simplify: 4π × 10⁻⁷/(2π) = 2 × 10⁻⁷.", "misconception": "Cancellation error when dividing 4π by 2π"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a mass spectrometer, singly ionized ions of two isotopes of an element (masses m₁ = 20 u and m₂ = 22 u, where 1 u = 1.66 × 10⁻²⁷ kg) are accelerated through a potential difference of 10 kV and then enter a uniform magnetic field of 0.2 T perpendicular to their velocity. The ions travel in semicircular paths and strike a photographic plate. What is the separation between the two lines formed on the photographic plate?", "explanation": "After acceleration, KE = qV, so v = √(2qV/m). The radius of the semicircular path is r = mv/(qB) = (m/(qB))√(2qV/m) = √(2mV/q)/B. The separation on the plate equals the difference in diameters: Δx = 2r₂ − 2r₁ = (2/B)√(2V/q)(√m₂ − √m₁). With q = 1.6 × 10⁻¹⁹ C, V = 10⁴ V, B = 0.2 T: √(2V/q) = √(2 × 10⁴/(1.6 × 10⁻¹⁹)) = √(1.25 × 10²³) = 1.118 × 10¹¹·⁵. Computing: r = √(2mV/q)/B. For m₁ = 20 × 1.66 × 10⁻²⁷ = 3.32 × 10⁻²⁶ kg: r₁ = √(2 × 3.32 × 10⁻²⁶ × 10⁴/1.6 × 10⁻¹⁹)/0.2 = √(4.15 × 10⁻³)/0.2 = 0.0644/0.2 = 0.322 m. For m₂ = 22 × 1.66 × 10⁻²⁷ = 3.652 × 10⁻²⁶ kg: r₂ = √(2 × 3.652 × 10⁻²⁶ × 10⁴/1.6 × 10⁻¹⁹)/0.2 = √(4.565 × 10⁻³)/0.2 = 0.0676/0.2 = 0.338 m. Separation = 2(r₂ − r₁) = 2(0.338 − 0.322) = 2 × 0.016 = 0.032 m ≈ 3.2 cm.", "correct_answer": "B", "concept_tags": ["mass-spectrometer", "isotopes", "semicircular-path", "separation", "scenario-based"], "payload": {"question_id": "cuet-phy-mag-force-37", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "1.6 cm", "is_correct": false}, {"key": "B", "text": "3.2 cm", "is_correct": true}, {"key": "C", "text": "6.4 cm", "is_correct": false}, {"key": "D", "text": "0.8 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.6 cm is the difference in radii (r₂ − r₁), not diameters. The separation on the photographic plate equals the difference in diameters: 2(r₂ − r₁).", "misconception": "Forgetting to multiply the radius difference by 2 for the diameter difference"}, {"option_key": "C", "hint": "6.4 cm is double the correct answer. Check that you are not multiplying by 4 instead of 2 when converting from radius to diameter difference.", "misconception": "Doubling the diameter difference instead of the radius difference"}, {"option_key": "D", "hint": "0.8 cm is too small. This may result from an error in the calculation of radii or forgetting to use the correct mass values.", "misconception": "Arithmetic error in computing the radii"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "What is the maximum kinetic energy (in MeV) that the protons can achieve in this cyclotron? (1 MeV = 1.6 × 10⁻¹³ J)", "explanation": "The maximum speed is achieved when the proton reaches the edge of the dee: v_max = qBR/m = (1.6 × 10⁻¹⁹ × 1.5 × 0.5)/(1.67 × 10⁻²⁷) = (1.2 × 10⁻¹⁹)/(1.67 × 10⁻²⁷) = 7.19 × 10⁷ m/s. Maximum KE = ½mv² = ½ × 1.67 × 10⁻²⁷ × (7.19 × 10⁷)² = ½ × 1.67 × 10⁻²⁷ × 5.17 × 10¹⁵ = 4.32 × 10⁻¹² J. Converting to MeV: 4.32 × 10⁻¹² / 1.6 × 10⁻¹³ = 27 MeV. Alternatively, KE = q²B²R²/(2m) = (1.6 × 10⁻¹⁹)² × (1.5)² × (0.5)² / (2 × 1.67 × 10⁻²⁷) = (2.56 × 10⁻³⁸ × 2.25 × 0.25)/(3.34 × 10⁻²⁷) = 1.44 × 10⁻³⁸/(3.34 × 10⁻²⁷) ≈ 4.31 × 10⁻¹² J ≈ 27 MeV.", "correct_answer": "C", "concept_tags": ["cyclotron", "maximum-kinetic-energy", "proton-acceleration", "dee-radius"], "payload": {"question_id": "cuet-phy-mag-force-38", "subtopic": "cyclotron", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "13.5 MeV", "is_correct": false}, {"key": "B", "text": "54 MeV", "is_correct": false}, {"key": "C", "text": "27 MeV", "is_correct": true}, {"key": "D", "text": "6.75 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is half the correct answer. Ensure you are using KE = q²B²R²/(2m) and not missing any squared term.", "misconception": "Missing the square on one of the quantities in the KE formula"}, {"option_key": "B", "hint": "This is double the correct answer. Check the factor of 2 in the denominator of KE = ½mv².", "misconception": "Forgetting the factor of ½ in the kinetic energy formula"}, {"option_key": "D", "hint": "This is one-fourth of the correct value. Verify that you have squared both B and R in the formula.", "misconception": "Forgetting to square the magnetic field or radius"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "easy", "question_text": "Arrange the following steps in the correct order for determining the force on a current-carrying conductor placed in a magnetic field using the formula F = BIL sinθ.", "explanation": "The correct sequence is: (Step 2) First identify the given quantities: B, I, and L. (Step 4) Determine the angle θ between the current direction and the magnetic field. (Step 1) Substitute all values into F = BIL sinθ to calculate the magnitude. (Step 3) Finally, use Fleming''s left-hand rule to find the direction of the force.", "correct_answer": "B", "concept_tags": ["force-calculation-steps", "BIL-formula", "flemings-rule"], "payload": {"question_id": "cuet-phy-mag-force-39", "subtopic": "force on current-carrying conductor (F=BIL sinθ)", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "2 → 1 → 4 → 3", "is_correct": false}, {"key": "B", "text": "2 → 4 → 1 → 3", "is_correct": true}, {"key": "C", "text": "4 → 2 → 3 → 1", "is_correct": false}, {"key": "D", "text": "3 → 2 → 4 → 1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "You cannot calculate F = BIL sinθ (step 1) before determining θ (step 4). The angle is needed for the substitution.", "misconception": "Attempting calculation before all variables are identified"}, {"option_key": "C", "hint": "You should identify B, I, and L (step 2) before determining the angle (step 4), as you need to know the setup first.", "misconception": "Starting with angle determination before understanding the physical setup"}, {"option_key": "D", "hint": "Fleming''s rule (step 3) gives direction, which is typically determined after computing the magnitude. You also need B and I first.", "misconception": "Determining force direction before identifying the physical quantities"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following phenomena in order of increasing magnetic force experienced, from least to greatest, for identical charged particles (charge q, mass m) moving with speed v.", "explanation": "The magnetic force on a charged particle is F = qvB sinθ. As the angle θ between v and B increases from 0° to 90°, sinθ increases from 0 to 1. At θ = 0° (parallel): F = 0. At θ = 30°: F = 0.5qvB. At θ = 60°: F = 0.866qvB. At θ = 90° (perpendicular): F = qvB (maximum). The order from least to greatest force is: parallel (0°) → 30° → 60° → perpendicular (90°), i.e., 1 → 2 → 3 → 4.", "correct_answer": "D", "concept_tags": ["angle-dependence", "sinθ-variation", "magnetic-force-comparison"], "payload": {"question_id": "cuet-phy-mag-force-40", "subtopic": "Lorentz force", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "4 → 3 → 2 → 1", "is_correct": false}, {"key": "B", "text": "1 → 3 → 2 → 4", "is_correct": false}, {"key": "C", "text": "2 → 1 → 3 → 4", "is_correct": false}, {"key": "D", "text": "1 → 2 → 3 → 4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This is the order from greatest to least, but the question asks for least to greatest (increasing order).", "misconception": "Reversing the required ordering direction"}, {"option_key": "B", "hint": "sin60° > sin30°, so the force at 60° is greater than at 30°. Items 2 and 3 are in wrong order here.", "misconception": "Incorrectly ranking sin30° and sin60°"}, {"option_key": "C", "hint": "A particle moving parallel to B (item 1) has zero force, which is less than force at 30° (item 2). Item 1 should come first.", "misconception": "Thinking a parallel-moving particle experiences some force"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The deflection in a moving coil galvanometer is proportional to the current passing through it because the restoring torque is proportional to:", "explanation": "In a moving coil galvanometer, the restoring torque is provided by the phosphor-bronze spring and is proportional to the angle of deflection (τ = kθ). At equilibrium, the deflecting torque (NIAB) equals the restoring torque (kθ), giving θ = (NAB/k)I. Hence deflection is proportional to current because the restoring torque is proportional to the twist/deflection angle.", "correct_answer": "D", "concept_tags": ["moving coil galvanometer", "restoring torque", "deflection"], "payload": {"question_id": "cuet-phy-mag-devices-01", "subtopic": "working principle", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "The magnetic field intensity", "is_correct": false}, {"key": "B", "value": "The number of turns of the coil", "is_correct": false}, {"key": "C", "value": "The area of the coil", "is_correct": false}, {"key": "D", "value": "The angle of twist of the suspension", "is_correct": true}], "elimination_hints": ["Magnetic field, number of turns, and area are constants of the galvanometer—they don''t change with deflection.", "The restoring torque must vary with deflection for equilibrium to be achieved at different currents.", "Think about what physically changes as the coil rotates—only the twist angle changes."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The time period of a charged particle revolving in a cyclotron is independent of:", "explanation": "In a cyclotron, the time period T = 2πm/(qB). This expression shows that T depends only on mass (m), charge (q), and magnetic field (B). It does not depend on the speed or energy of the particle (non-relativistic case). This is the key principle that makes the cyclotron work -- particles take the same time per revolution regardless of their speed, allowing a fixed-frequency oscillating electric field to accelerate them.", "correct_answer": "C", "concept_tags": ["cyclotron-frequency", "time-period", "independence-of-speed"], "payload": {"question_id": "cuet-phy-mag-devices-02", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "Mass of the particle", "is_correct": false}, {"key": "B", "text": "Magnetic field strength", "is_correct": false}, {"key": "C", "text": "Speed of the particle", "is_correct": true}, {"key": "D", "text": "Charge of the particle", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The formula T = 2πm/(qB) explicitly contains mass m in the numerator, so the time period directly depends on mass.", "misconception": "Overlooking the mass dependence in the cyclotron frequency formula"}, {"option_key": "B", "hint": "Magnetic field B appears in the denominator of T = 2πm/(qB). Increasing B decreases the time period, so T depends on B.", "misconception": "Ignoring the role of magnetic field in determining the cyclotron period"}, {"option_key": "D", "hint": "Charge q is in the denominator of T = 2πm/(qB). A particle with larger charge has a shorter time period, so T does depend on charge.", "misconception": "Forgetting that charge influences the cyclotron frequency"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The material used for the suspension wire in a moving coil galvanometer is phosphor-bronze because it has:", "explanation": "Phosphor-bronze is used for the suspension wire/spring in a moving coil galvanometer because it has a very small restoring torque per unit twist (low torsional constant). This ensures high sensitivity—even a small current produces a noticeable deflection. While it is also non-magnetic and has low temperature coefficient, the primary reason is the small restoring torque.", "correct_answer": "B", "concept_tags": ["galvanometer construction", "phosphor-bronze", "sensitivity"], "payload": {"question_id": "cuet-phy-mag-devices-03", "subtopic": "Galvanometer construction", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "High electrical conductivity", "is_correct": false}, {"key": "B", "value": "Small restoring torque per unit twist", "is_correct": true}, {"key": "C", "value": "High magnetic permeability", "is_correct": false}, {"key": "D", "value": "Large Young''s modulus", "is_correct": false}], "elimination_hints": ["Copper has higher conductivity but is not used—so conductivity is not the key property.", "High magnetic permeability would interfere with the magnetic field, making it undesirable.", "Large Young''s modulus means stiffness, which would reduce sensitivity, not improve it."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In a moving coil galvanometer, the coil is wound on an aluminium frame to:", "explanation": "The coil in a moving coil galvanometer is wound on an aluminium frame to provide electromagnetic damping. When the coil rotates in the magnetic field, eddy currents are induced in the aluminium frame (which is a conductor). These eddy currents oppose the motion of the coil (by Lenz''s law), bringing the coil to rest quickly without oscillations. This is known as dead-beat behavior.", "correct_answer": "B", "concept_tags": ["electromagnetic damping", "eddy currents", "aluminium frame"], "payload": {"question_id": "cuet-phy-mag-devices-04", "subtopic": "Galvanometer construction", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "Increase the magnetic flux through the coil", "is_correct": false}, {"key": "B", "value": "Provide electromagnetic damping", "is_correct": true}, {"key": "C", "value": "Increase the moment of inertia of the coil", "is_correct": false}, {"key": "D", "value": "Make the coil lighter", "is_correct": false}], "elimination_hints": ["The frame is made of aluminium (a conductor)—think about what happens when a conductor moves in a magnetic field.", "Increasing moment of inertia would slow the response, which is not desirable.", "If making the coil lighter were the goal, a non-metallic frame would be even lighter."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A cyclotron is used to accelerate:", "explanation": "A cyclotron is used to accelerate charged particles such as protons, deuterons, and alpha particles. It cannot accelerate neutral particles (no Lorentz force) or electrons (their small mass causes relativistic effects at modest energies, making the cyclotron frequency condition invalid). The device uses a combination of electric and magnetic fields to accelerate charged particles to high energies.", "correct_answer": "B", "concept_tags": ["cyclotron", "charged-particles", "particle-accelerator"], "payload": {"question_id": "cuet-phy-mag-devices-05", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "Electrons", "is_correct": false}, {"key": "B", "text": "Protons and deuterons", "is_correct": true}, {"key": "C", "text": "Neutral atoms", "is_correct": false}, {"key": "D", "text": "Neutrons", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small mass (9.1 x 10^-31 kg), so they quickly reach relativistic speeds where their mass increases significantly, violating the constant cyclotron frequency condition.", "misconception": "Thinking cyclotron works for all charged particles regardless of mass"}, {"option_key": "C", "hint": "Neutral atoms have no net charge, so they experience no Lorentz force (F = qv x B = 0) and cannot be accelerated by electric or magnetic fields.", "misconception": "Forgetting that cyclotron requires charged particles"}, {"option_key": "D", "hint": "Neutrons are uncharged particles. The cyclotron relies on the magnetic force (qvB) to bend particle paths, which is zero for neutral particles.", "misconception": "Confusing neutrons with charged particles"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "To convert a galvanometer into a voltmeter, one should connect:", "explanation": "A galvanometer is converted into a voltmeter by connecting a high resistance in series with it. This limits the current through the galvanometer to its full-scale deflection current (Ig) when the desired maximum voltage V is applied. The required series resistance R = V/Ig - G, where G is the galvanometer resistance. The high series resistance ensures that the voltmeter draws negligible current from the circuit.", "correct_answer": "A", "concept_tags": ["galvanometer-conversion", "voltmeter", "series-resistance"], "payload": {"question_id": "cuet-phy-mag-devices-06", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "A high resistance in series", "is_correct": true}, {"key": "B", "text": "A low resistance in series", "is_correct": false}, {"key": "C", "text": "A high resistance in parallel", "is_correct": false}, {"key": "D", "text": "A low resistance in parallel", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A low resistance in series would barely increase the total resistance, so the galvanometer would still draw too much current and could be damaged. The resistance must be high to limit current to Ig.", "misconception": "Not understanding that a voltmeter must have very high resistance"}, {"option_key": "C", "hint": "A high resistance in parallel would have little effect since most current would still flow through the lower-resistance galvanometer. Parallel connection is used for ammeter conversion.", "misconception": "Confusing series and parallel configurations for meter conversion"}, {"option_key": "D", "hint": "A low resistance in parallel (shunt) is used to convert a galvanometer into an ammeter, not a voltmeter.", "misconception": "Confusing ammeter and voltmeter conversion methods"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When a shunt of resistance S is connected across a galvanometer of resistance G, the fraction of total current that passes through the galvanometer is:", "explanation": "When a shunt S is connected in parallel with galvanometer G, the current divides in the inverse ratio of resistances. The current through galvanometer Ig = I × S/(G + S). Therefore, the fraction Ig/I = S/(G + S). This shows that a smaller shunt diverts more current away from the galvanometer.", "correct_answer": "D", "concept_tags": ["shunt resistance", "current division", "parallel circuit"], "payload": {"question_id": "cuet-phy-mag-devices-07", "subtopic": "shunt resistance", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "G/(G + S)", "is_correct": false}, {"key": "B", "value": "G/S", "is_correct": false}, {"key": "C", "value": "S/G", "is_correct": false}, {"key": "D", "value": "S/(G + S)", "is_correct": true}], "elimination_hints": ["In a parallel combination, current through a branch is inversely proportional to its resistance.", "The galvanometer has resistance G, so less current flows through it when G is large—the fraction should decrease with increasing G.", "Check: if S = G, the fraction should be 1/2 (equal split). Only S/(G + S) gives G/(G+G) = 1/2."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a moving coil galvanometer, the restoring torque is provided by:", "explanation": "In a moving coil galvanometer, the coil experiences a deflecting torque (τ = NIAB) due to the magnetic field. The restoring torque is provided by a pair of phosphor-bronze springs (hair springs) attached to the coil. At equilibrium, the restoring torque (kθ) equals the deflecting torque (NIAB), giving θ = NIAB/k. The springs also serve as leads to carry current to and from the coil.", "correct_answer": "D", "concept_tags": ["moving-coil-galvanometer", "restoring-torque", "spring", "equilibrium"], "payload": {"question_id": "cuet-phy-mag-devices-08", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "The magnetic field", "is_correct": false}, {"key": "B", "text": "Gravity", "is_correct": false}, {"key": "C", "text": "The soft iron core", "is_correct": false}, {"key": "D", "text": "The phosphor-bronze spring", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The magnetic field produces the deflecting torque (τ = NIAB), not the restoring torque. The restoring mechanism must oppose the deflection.", "misconception": "Confusing deflecting torque with restoring torque"}, {"option_key": "B", "hint": "Gravity is not used as the restoring mechanism in a moving coil galvanometer. The instrument can work in any orientation because springs provide the restoring torque.", "misconception": "Confusing with gravity-based instruments"}, {"option_key": "C", "hint": "The soft iron core makes the magnetic field radial (uniform in all positions of the coil) to ensure linear deflection, but it does not provide the restoring torque.", "misconception": "Confusing the role of the iron core with the spring"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer of resistance 100 Ω gives full-scale deflection for a current of 10 mA. The resistance to be connected in series to convert it into a voltmeter of range 0-100 V is:", "explanation": "To convert a galvanometer to a voltmeter, a high resistance R is connected in series. Using R = V/Ig - G, where V = 100 V, Ig = 10 mA = 0.01 A, and G = 100 Ω: R = 100/0.01 - 100 = 10000 - 100 = 9900 Ω. The total resistance of the voltmeter becomes G + R = 10000 Ω, ensuring that only Ig flows when V is applied across it.", "correct_answer": "D", "concept_tags": ["galvanometer-to-voltmeter", "series-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-devices-09", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "10000 Ω", "is_correct": false}, {"key": "B", "text": "1000 Ω", "is_correct": false}, {"key": "C", "text": "10 Ω", "is_correct": false}, {"key": "D", "text": "9900 Ω", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10000 Ω is V/Ig = 100/0.01, which is the total resistance needed. But the question asks for the series resistance R alone, so you must subtract G: R = 10000 - 100 = 9900 Ω.", "misconception": "Forgetting to subtract the galvanometer resistance G from V/Ig"}, {"option_key": "B", "hint": "1000 Ω would give a total resistance of 1100 Ω, limiting the voltmeter range to only V = Ig x (G + R) = 0.01 x 1100 = 11 V, not 100 V.", "misconception": "Arithmetic error or using wrong formula"}, {"option_key": "C", "hint": "10 Ω is far too small. With R = 10 Ω, total resistance = 110 Ω, giving range V = 0.01 x 110 = 1.1 V only.", "misconception": "Confusing voltmeter conversion with ammeter conversion (where low resistance is used)"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer has a resistance of 50 Ω and gives full-scale deflection for a current of 5 mA. To convert it into an ammeter reading up to 5 A, the shunt resistance required is:", "explanation": "To convert a galvanometer into an ammeter, a low resistance (shunt) S is connected in parallel. Using the formula S = Ig × G / (I − Ig), where Ig = 5 mA = 0.005 A, G = 50 Ω, and I = 5 A: S = (0.005 × 50) / (5 − 0.005) = 0.25 / 4.995 ≈ 0.05 Ω. Since 4.995 ≈ 5, we get S ≈ 0.05 Ω.", "correct_answer": "C", "concept_tags": ["ammeter conversion", "shunt resistance", "galvanometer"], "payload": {"question_id": "cuet-phy-mag-devices-10", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "0.5 Ω", "is_correct": false}, {"key": "B", "value": "0.005 Ω", "is_correct": false}, {"key": "C", "value": "0.05 Ω", "is_correct": true}, {"key": "D", "value": "5 Ω", "is_correct": false}], "elimination_hints": ["The shunt must be very small compared to the galvanometer resistance of 50 Ω.", "5 Ω is too large—it would not divert enough current away from the galvanometer.", "Use S = IgG/(I−Ig) and approximate I−Ig ≈ I when I >> Ig."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current sensitivity of a galvanometer can be increased by:", "explanation": "Current sensitivity is defined as θ/I = NAB/k. To increase it, we can increase N (number of turns), A (area of coil), B (magnetic field strength), or decrease k (torsional constant of the spring). Using a stronger magnetic field directly increases current sensitivity.", "correct_answer": "C", "concept_tags": ["current sensitivity", "galvanometer sensitivity"], "payload": {"question_id": "cuet-phy-mag-devices-11", "subtopic": "current sensitivity", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "Increasing the torsional constant of the spring", "is_correct": false}, {"key": "B", "value": "Decreasing the number of turns in the coil", "is_correct": false}, {"key": "C", "value": "Using a stronger magnetic field", "is_correct": true}, {"key": "D", "value": "Reducing the area of the coil", "is_correct": false}], "elimination_hints": ["Current sensitivity = NAB/k. Increasing k (denominator) would decrease sensitivity.", "Decreasing N or A would reduce the numerator, thus reducing sensitivity.", "Only an option that increases NAB or decreases k will increase sensitivity."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current sensitivity of a moving coil galvanometer can be increased by:", "explanation": "Current sensitivity Is = NAB/k, where N is the number of turns, A is the area of the coil, B is the magnetic field strength, and k is the torsional spring constant. To increase current sensitivity, we can increase N, A, or B, or decrease k (use a weaker spring). Increasing the spring constant k would decrease the sensitivity, not increase it.", "correct_answer": "C", "concept_tags": ["current-sensitivity", "galvanometer", "NAB-by-k"], "payload": {"question_id": "cuet-phy-mag-devices-12", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "Increasing the spring constant k", "is_correct": false}, {"key": "B", "text": "Decreasing the number of turns N", "is_correct": false}, {"key": "C", "text": "Increasing the magnetic field strength B", "is_correct": true}, {"key": "D", "text": "Decreasing the area of the coil A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since Is = NAB/k, increasing k (denominator) would decrease the sensitivity, making the galvanometer less sensitive to small currents.", "misconception": "Confusing direct and inverse proportionality in the sensitivity formula"}, {"option_key": "B", "hint": "N appears in the numerator of Is = NAB/k. Decreasing N would reduce sensitivity, not increase it.", "misconception": "Incorrectly identifying N as being in the denominator"}, {"option_key": "D", "hint": "Area A is in the numerator of Is = NAB/k. A larger coil area increases the torque for a given current, increasing sensitivity.", "misconception": "Thinking smaller area gives better sensitivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The voltage sensitivity of a galvanometer of resistance G, having N turns of area A in magnetic field B with spring constant k is given by:", "explanation": "Voltage sensitivity Vs = deflection per unit voltage = θ/V. Since θ/I (current sensitivity) = NAB/k, and V = IR (where R is the total resistance = G for the galvanometer alone), we get Vs = θ/V = (θ/I) x (1/G) = NAB/(kG). Thus voltage sensitivity depends inversely on the galvanometer resistance, unlike current sensitivity.", "correct_answer": "C", "concept_tags": ["voltage-sensitivity", "galvanometer", "NAB-by-kG"], "payload": {"question_id": "cuet-phy-mag-devices-13", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "NAB/k", "is_correct": false}, {"key": "B", "text": "NABk/G", "is_correct": false}, {"key": "C", "text": "NAB/(kG)", "is_correct": true}, {"key": "D", "text": "NAG/(kB)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "NAB/k is the current sensitivity (θ/I), not the voltage sensitivity. Voltage sensitivity = current sensitivity / G = NAB/(kG).", "misconception": "Confusing current sensitivity with voltage sensitivity"}, {"option_key": "B", "hint": "This expression has k in the numerator. Since higher spring constant k means lower deflection per unit current, k must be in the denominator.", "misconception": "Placing k incorrectly in the formula"}, {"option_key": "D", "hint": "This expression has G in the numerator and B in the denominator, both of which are inverted. Higher B gives more torque (hence more sensitivity), and higher G gives less voltage sensitivity.", "misconception": "Swapping the positions of B and G"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A cyclotron''s oscillator frequency is 10 MHz. If the magnetic field is 0.5 T, the charge-to-mass ratio (q/m) of the particle being accelerated is approximately:", "explanation": "The cyclotron frequency is given by f = qB/(2πm), so q/m = 2πf/B. Substituting the values: q/m = 2π x 10 x 10^6 / 0.5 = 2 x 3.14 x 10^7 / 0.5 = 6.28 x 10^7 / 0.5 = 1.256 x 10^8 C/kg ≈ 1.26 x 10^8 C/kg. This is close to the q/m ratio of a proton (e/mp = 1.6 x 10^-19 / 1.67 x 10^-27 ≈ 0.96 x 10^8 C/kg), suggesting a slightly different ion.", "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "charge-to-mass-ratio", "numerical"], "payload": {"question_id": "cuet-phy-mag-devices-14", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 x 10^7 C/kg", "is_correct": false}, {"key": "B", "text": "1.26 x 10^8 C/kg", "is_correct": true}, {"key": "C", "text": "3.14 x 10^8 C/kg", "is_correct": false}, {"key": "D", "text": "2.0 x 10^7 C/kg", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This value (6.28 x 10^7) equals 2πf but forgets to divide by B. The correct formula is q/m = 2πf/B, and you must divide by 0.5 T.", "misconception": "Forgetting to divide by the magnetic field B"}, {"option_key": "C", "hint": "This value (3.14 x 10^8) corresponds to dividing by B but using πf instead of 2πf, or an arithmetic error in the multiplication.", "misconception": "Incorrect substitution in the cyclotron frequency formula"}, {"option_key": "D", "hint": "This value is significantly off from the correct calculation. With f = 10^7 Hz and B = 0.5 T, q/m = 2π x 10^7 / 0.5 = 4π x 10^7 ≈ 1.26 x 10^8.", "misconception": "Major arithmetic error or using the wrong formula"}]}}]'::jsonb, 'deploy-2026-03-05-b09');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer has a resistance of 50 Ω and gives full-scale deflection for a current of 1 mA. To convert it into an ammeter of range 0 to 5 A, the shunt resistance required is:", "explanation": "To convert a galvanometer to an ammeter, a shunt resistance S is connected in parallel. Using the formula S = Ig x G/(I - Ig), where Ig = 1 mA = 0.001 A, G = 50 Ω, and I = 5 A: S = 0.001 x 50 / (5 - 0.001) = 0.05 / 4.999 ≈ 0.01 Ω. Since Ig << I, we can approximate S ≈ Ig x G / I = 0.001 x 50 / 5 = 0.01 Ω.", "correct_answer": "A", "concept_tags": ["galvanometer-to-ammeter", "shunt-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-devices-15", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "0.01 Ω", "is_correct": true}, {"key": "B", "text": "0.05 Ω", "is_correct": false}, {"key": "C", "text": "1.0 Ω", "is_correct": false}, {"key": "D", "text": "50 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "0.05 Ω = Ig x G = 0.001 x 50. This is the numerator of the formula but you must divide by (I - Ig) ≈ 5 to get the shunt value.", "misconception": "Using S = Ig x G instead of the complete formula S = Ig x G/(I - Ig)"}, {"option_key": "C", "hint": "1.0 Ω is too high for a shunt. The shunt must be much smaller than the galvanometer resistance to divert most current away from the coil.", "misconception": "Not understanding that shunt resistance should be very small"}, {"option_key": "D", "hint": "Using S = G = 50 Ω means equal resistance in parallel, which would only double the range, not increase it 5000 times.", "misconception": "Thinking the shunt should equal the galvanometer resistance"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The maximum kinetic energy of a charged particle emerging from a cyclotron of radius R, magnetic field B, charge q, and mass m is:", "explanation": "In a cyclotron, the charged particle moves in a circular path where the magnetic force provides centripetal force: qvB = mv^2/R, giving v = qBR/m. The maximum kinetic energy is KE = (1/2)mv^2 = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m). Here R is the radius of the largest semicircular path (the dee radius).", "correct_answer": "A", "concept_tags": ["cyclotron", "kinetic-energy", "maximum-energy", "dee-radius"], "payload": {"question_id": "cuet-phy-mag-devices-16", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "q²B²R²/(2m)", "is_correct": true}, {"key": "B", "text": "qBR/(2m)", "is_correct": false}, {"key": "C", "text": "q²B²R²/(m)", "is_correct": false}, {"key": "D", "text": "qB²R²/(2m)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This expression has dimensions of velocity (m/s), not energy (kg m^2/s^2). The kinetic energy must involve squared terms of q, B, and R.", "misconception": "Confusing the expression for velocity with kinetic energy"}, {"option_key": "C", "hint": "This is twice the correct answer. KE = (1/2)mv^2 has the factor of 1/2, so the result should be q^2B^2R^2/(2m), not q^2B^2R^2/m.", "misconception": "Forgetting the factor of 1/2 in the kinetic energy formula"}, {"option_key": "D", "hint": "This expression is missing one factor of q. Since v = qBR/m, the KE = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m), requiring q squared.", "misconception": "Error in squaring the velocity expression"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer of resistance 40 Ω gives full-scale deflection for a current of 2 mA. It is converted into a voltmeter of range 0–20 V and also into an ammeter of range 0–5 A. The ratio of the resistance of the voltmeter to the resistance of the ammeter is:", "explanation": "For the voltmeter: Total resistance Rv = V/Ig = 20/0.002 = 10,000 Ω. For the ammeter: The shunt S = IgG/(I − Ig) = (0.002 × 40)/(5 − 0.002) = 0.08/4.998 ≈ 0.016 Ω. Total ammeter resistance Ra = GS/(G + S) ≈ S = 0.016 Ω (since S << G). Ratio Rv/Ra = 10,000/0.016 = 625,000. Alternatively, Rv/Ra = (V/Ig) / [IgG/(I−Ig)] = V(I−Ig)/(Ig²G) ≈ VI/(Ig²G) = (20 × 5)/(0.000004 × 40) = 100/0.00016 = 625,000.", "correct_answer": "D", "concept_tags": ["voltmeter resistance", "ammeter resistance", "conversion"], "payload": {"question_id": "cuet-phy-mag-devices-17", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "250", "is_correct": false}, {"key": "B", "value": "2,500", "is_correct": false}, {"key": "C", "value": "62,500", "is_correct": false}, {"key": "D", "value": "625,000", "is_correct": true}], "elimination_hints": ["A voltmeter has very high resistance, an ammeter has very low resistance—the ratio should be a very large number.", "Options like 250 or 2,500 are too small for the ratio of a 10,000 Ω voltmeter to a ~0.016 Ω ammeter.", "Calculate each resistance separately: Rv = V/Ig and Ra ≈ IgG/I, then find the ratio."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer has a coil of 200 turns, each of area 1.5 × 10⁻² m², and is placed in a magnetic field of 0.2 T. If the torsional constant of the spring is 1.2 N·m/rad, what is the current required to produce a deflection of 30°?", "explanation": "At equilibrium, NIAB = kθ. Converting 30° to radians: θ = 30 × π/180 = π/6 rad ≈ 0.5236 rad. So I = kθ/(NAB) = (1.2 × 0.5236)/(200 × 1.5 × 10⁻² × 0.2) = 0.6283/(200 × 0.003) = 0.6283/0.6 = 1.047 A ≈ 1.05 A.", "correct_answer": "D", "concept_tags": ["galvanometer deflection", "torque balance", "numerical problem"], "payload": {"question_id": "cuet-phy-mag-devices-18", "subtopic": "working principle", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "0.52 A", "is_correct": false}, {"key": "B", "value": "2.10 A", "is_correct": false}, {"key": "C", "value": "0.63 A", "is_correct": false}, {"key": "D", "value": "1.05 A", "is_correct": true}], "elimination_hints": ["Remember to convert degrees to radians: 30° = π/6 rad, not 30 directly.", "0.52 A would be the answer if you forgot to convert degrees to radians (using θ = 30 without conversion would give a different error).", "I = kθ/(NAB). Compute NAB = 200 × 0.015 × 0.2 = 0.6. Then I = 1.2 × (π/6) / 0.6."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer of resistance 50 Ω and full-scale deflection current 2 mA is to be converted into an ammeter of range 0-10 A and a voltmeter of range 0-200 V. The ratio of shunt resistance to series resistance is:", "explanation": "For ammeter: S = Ig x G/(I - Ig) = 0.002 x 50/(10 - 0.002) ≈ 0.1/9.998 ≈ 0.01 Ω. For voltmeter: R = V/Ig - G = 200/0.002 - 50 = 100000 - 50 = 99950 Ω. Ratio S/R = 0.01/99950 ≈ 1 x 10^-7. Alternatively, S/R = [Ig x G/(I - Ig)] / [V/Ig - G] ≈ [Ig x G/I] / [V/Ig] = Ig^2 x G / (IV) = (0.002)^2 x 50 / (10 x 200) = 2 x 10^-7 / 2000 = 1 x 10^-7.", "correct_answer": "D", "concept_tags": ["ammeter-voltmeter-conversion", "shunt", "series-resistance", "ratio"], "payload": {"question_id": "cuet-phy-mag-devices-19", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 x 10^-3", "is_correct": false}, {"key": "B", "text": "1 x 10^-5", "is_correct": false}, {"key": "C", "text": "1 x 10^-6", "is_correct": false}, {"key": "D", "text": "1 x 10^-7", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This would imply the shunt is only 1000 times smaller than the series resistance. Given the huge difference in conversion (ammeter needs ~0.01 Ω, voltmeter needs ~100000 Ω), the ratio should be much smaller.", "misconception": "Rough estimation without proper calculation"}, {"option_key": "B", "hint": "Verify your calculation: S ≈ 0.01 Ω and R ≈ 99950 Ω. The ratio 0.01/99950 is approximately 10^-7, not 10^-5.", "misconception": "Arithmetic error in the order of magnitude"}, {"option_key": "C", "hint": "Close but off by a factor of 10. Carefully recalculate: S/R = 0.01/99950 ≈ 1.0 x 10^-7.", "misconception": "Small arithmetic or rounding error"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A proton is accelerated in a cyclotron with magnetic field 1.5 T. The radius of the dees is 0.5 m. The maximum kinetic energy gained by the proton is approximately (mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C):", "explanation": "Maximum KE = q^2B^2R^2/(2m). Substituting: KE = (1.6 x 10^-19)^2 x (1.5)^2 x (0.5)^2 / (2 x 1.67 x 10^-27) = (2.56 x 10^-38) x 2.25 x 0.25 / (3.34 x 10^-27) = (2.56 x 10^-38 x 0.5625) / (3.34 x 10^-27) = 1.44 x 10^-38 / 3.34 x 10^-27 = 4.31 x 10^-12 J. Converting to MeV: 4.31 x 10^-12 / 1.6 x 10^-13 ≈ 26.9 MeV ≈ 27 MeV.", "correct_answer": "C", "concept_tags": ["cyclotron", "maximum-kinetic-energy", "proton", "numerical-calculation"], "payload": {"question_id": "cuet-phy-mag-devices-20", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "7 MeV", "is_correct": false}, {"key": "B", "text": "14 MeV", "is_correct": false}, {"key": "C", "text": "27 MeV", "is_correct": true}, {"key": "D", "text": "54 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "7 MeV is approximately 1/4 of the correct answer. Check if you used R = 0.25 m instead of 0.5 m, or missed squaring one of the terms.", "misconception": "Using R instead of R^2 in the kinetic energy formula"}, {"option_key": "B", "hint": "14 MeV is half the correct answer. Ensure you have squared both q and B correctly in q^2B^2R^2/(2m).", "misconception": "Forgetting to square one of the quantities"}, {"option_key": "D", "hint": "54 MeV is double the correct answer. Check that you included the factor of 2 in the denominator of KE = q^2B^2R^2/(2m).", "misconception": "Forgetting the factor of 1/2 in the kinetic energy expression"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a moving coil galvanometer with a cylindrical soft iron core placed between the poles of a permanent magnet. What is the primary purpose of the cylindrical soft iron core?", "explanation": "The cylindrical soft iron core serves to make the magnetic field radial. When placed between concave-shaped pole pieces, the soft iron core ensures that the plane of the coil is always parallel to the magnetic field direction, regardless of the coil''s rotational position. This makes the deflecting torque τ = NIAB sin 90° = NIAB, ensuring a linear relationship between current and deflection throughout the range of motion.", "correct_answer": "D", "concept_tags": ["soft iron core", "radial field", "galvanometer construction"], "payload": {"question_id": "cuet-phy-mag-devices-21", "subtopic": "Galvanometer construction", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "To increase the electrical resistance of the coil", "is_correct": false}, {"key": "B", "value": "To provide a restoring torque to the coil", "is_correct": false}, {"key": "C", "value": "To increase the moment of inertia of the coil", "is_correct": false}, {"key": "D", "value": "To make the magnetic field radial and uniform", "is_correct": true}], "elimination_hints": ["The core is made of soft iron (a magnetic material), not a resistor—so it doesn''t affect electrical resistance.", "The restoring torque is provided by the suspension wire/spring, not the core.", "Increasing moment of inertia would slow the response—this would be a disadvantage, not a purpose."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a galvanometer G of resistance 20 Ω connected with a shunt resistance S in parallel. If the galvanometer gives full-scale deflection for 10 mA and the shunt carries 90 mA, what is the value of S?", "explanation": "Since the galvanometer and shunt are in parallel, the voltage across both is equal: Ig × G = Is × S. Here Ig = 10 mA, G = 20 Ω, and Is = 90 mA. So S = (Ig × G)/Is = (10 × 20)/90 = 200/90 = 20/9 ≈ 2.22 Ω.", "correct_answer": "C", "concept_tags": ["shunt resistance", "ammeter conversion", "parallel circuit"], "payload": {"question_id": "cuet-phy-mag-devices-22", "subtopic": "shunt resistance", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "2 Ω", "is_correct": false}, {"key": "B", "value": "0.22 Ω", "is_correct": false}, {"key": "C", "value": "20/9 Ω", "is_correct": true}, {"key": "D", "value": "9/20 Ω", "is_correct": false}], "elimination_hints": ["Use the equal voltage condition: Ig × G = Is × S, so S = IgG/Is.", "S = (10 × 20)/90 = 200/90. Simplify: 200/90 = 20/9.", "Option D (9/20 Ω) is the reciprocal of the correct answer—a common trap in fraction-based problems."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The circuit diagram shows a galvanometer G (resistance 100 Ω, full-scale deflection current 1 mA) connected with a resistance R in series, and this combination is connected across a battery of emf 10 V. What value of R converts the galvanometer into a voltmeter of range 0–10 V?", "explanation": "To convert a galvanometer into a voltmeter of range V, a high resistance R is connected in series. Using V = Ig(G + R): 10 = 0.001 × (100 + R), so 100 + R = 10000, giving R = 9900 Ω = 9.9 kΩ. The high series resistance ensures very little current is drawn from the circuit being measured.", "correct_answer": "B", "concept_tags": ["voltmeter conversion", "series resistance", "galvanometer"], "payload": {"question_id": "cuet-phy-mag-devices-23", "subtopic": "conversion to voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "10,000 Ω", "is_correct": false}, {"key": "B", "value": "9,900 Ω", "is_correct": true}, {"key": "C", "value": "990 Ω", "is_correct": false}, {"key": "D", "value": "99,900 Ω", "is_correct": false}], "elimination_hints": ["R = V/Ig − G. Don''t forget to subtract the galvanometer resistance G from the total resistance.", "Total resistance needed = V/Ig = 10/0.001 = 10,000 Ω. Since G = 100 Ω, R = 10,000 − 100.", "990 Ω would give a voltmeter range of only about 1.09 V—too low for a 10 V range."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The diagram shows two galvanometers P and Q with identical coils (same N, A, B) but different spring constants. If kP = 2kQ, what is the ratio of their current sensitivities (θP/IP) : (θQ/IQ)?", "explanation": "Current sensitivity = θ/I = NAB/k. Since N, A, and B are the same for both galvanometers, the current sensitivity is inversely proportional to k. (θP/IP)/(θQ/IQ) = kQ/kP = kQ/(2kQ) = 1/2. Therefore, the ratio is 1:2. Galvanometer Q is more sensitive because it has a smaller spring constant.", "correct_answer": "B", "concept_tags": ["current sensitivity", "spring constant", "comparison"], "payload": {"question_id": "cuet-phy-mag-devices-24", "subtopic": "current sensitivity", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "value": "2 : 1", "is_correct": false}, {"key": "B", "value": "1 : 2", "is_correct": true}, {"key": "C", "value": "1 : 1", "is_correct": false}, {"key": "D", "value": "4 : 1", "is_correct": false}], "elimination_hints": ["Current sensitivity = NAB/k. Higher k means lower sensitivity.", "Since kP = 2kQ, P has a stiffer spring—so P should be LESS sensitive than Q.", "The ratio is inversely proportional to k values: (1/kP) : (1/kQ) = (1/2kQ) : (1/kQ) = 1 : 2."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): An ammeter is always connected in parallel with the circuit element through which current is to be measured.\nReason (R): An ammeter has very low resistance so that it does not significantly change the current in the circuit.", "explanation": "The assertion is false. An ammeter is always connected in series with the circuit element, not in parallel. If connected in parallel, its low resistance would create a short circuit. The reason is true—an ammeter does have very low resistance to minimize its effect on the circuit current. Since the assertion is false but the reason is true, the answer is D.", "correct_answer": "D", "concept_tags": ["ammeter", "series connection", "low resistance"], "payload": {"question_id": "cuet-phy-mag-devices-25", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "value": "Both A and R are true and R is the correct explanation of A", "is_correct": false}, {"key": "B", "value": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": true}], "elimination_hints": ["Think carefully: is an ammeter connected in series or parallel? A parallel connection with low resistance would short the element.", "The reason about low resistance is correct—ammeters must have low resistance to not alter the current being measured.", "Since the assertion contains a factual error (parallel instead of series), options A and B (which state A is true) can be eliminated."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Increasing the number of turns of the coil in a galvanometer increases current sensitivity but may not increase voltage sensitivity.\nReason (R): Voltage sensitivity equals current sensitivity divided by the resistance of the galvanometer, and increasing turns increases resistance.", "explanation": "Both the assertion and reason are true, and the reason correctly explains the assertion. Current sensitivity = NAB/k, which increases with N. However, voltage sensitivity = NAB/(kR). When N increases, the resistance R of the coil also increases (roughly proportionally). So voltage sensitivity = NAB/(kR) may not increase because the increase in N in the numerator is offset by the increase in R in the denominator. The reason correctly identifies this relationship.", "correct_answer": "A", "concept_tags": ["current sensitivity", "voltage sensitivity", "number of turns"], "payload": {"question_id": "cuet-phy-mag-devices-26", "subtopic": "voltage sensitivity", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "value": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "value": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": false}], "elimination_hints": ["Check current sensitivity formula: θ/I = NAB/k. Increasing N clearly increases this.", "Check voltage sensitivity formula: θ/V = NAB/(kR). If N doubles and R also doubles, voltage sensitivity stays the same.", "The reason provides the exact mathematical relationship that explains why voltage sensitivity may not increase—this makes R a correct explanation of A."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The cyclotron frequency does not depend on the speed of the charged particle. Reason (R): In a cyclotron, as the particle gains speed, the radius of its circular path increases proportionally, keeping the time period constant.", "explanation": "Both the Assertion and Reason are correct, and the Reason correctly explains the Assertion. The cyclotron frequency f = qB/(2πm) is independent of speed. This is because when a particle gains energy and moves faster (v increases), it moves to a larger radius orbit (r = mv/(qB)), so r increases proportionally with v. Since T = 2πr/v = 2πm/(qB), the v cancels out, making the period constant. This is the fundamental principle that allows the cyclotron to use a fixed-frequency oscillating electric field.", "correct_answer": "A", "concept_tags": ["cyclotron-frequency", "radius-speed-relation", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-mag-devices-27", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly explains why the frequency is independent of speed: the increase in radius exactly compensates for the increase in speed, so the time per revolution stays constant. This is a causal explanation.", "misconception": "Not recognizing the causal connection between the radius-speed relationship and constant frequency"}, {"option_key": "C", "hint": "The Reason is factually correct. In a cyclotron, r = mv/(qB), so r is directly proportional to v. The circumference (2πr) grows in proportion to v, keeping T = 2πr/v constant.", "misconception": "Doubting the relationship between radius and speed"}, {"option_key": "D", "hint": "The Assertion is correct: from f = qB/(2πm), the frequency clearly does not contain velocity v, confirming it is independent of speed.", "misconception": "Thinking cyclotron frequency depends on speed"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Increasing the number of turns in a moving coil galvanometer always increases both its current sensitivity and voltage sensitivity. Reason (R): Current sensitivity is NAB/k and voltage sensitivity is NAB/(kG), and increasing N increases the resistance G of the coil.", "explanation": "The Assertion is incorrect. While increasing N does increase current sensitivity (Is = NAB/k), it also increases the coil resistance G (since G is proportional to N for a given wire). Voltage sensitivity Vs = NAB/(kG) = Is/G. As N increases, both NAB/k and G increase, and the net effect on Vs depends on the relative rates. In fact, since G is proportional to N (longer wire), Vs = NAB/(kG) may remain roughly constant or even decrease. So increasing N does NOT always increase voltage sensitivity. The Reason is correct: it correctly states both formulas and that increasing N increases G.", "correct_answer": "D", "concept_tags": ["current-sensitivity", "voltage-sensitivity", "number-of-turns", "galvanometer-design"], "payload": {"question_id": "cuet-phy-mag-devices-28", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The Assertion claims increasing N always increases both sensitivities. But since G also increases with N, voltage sensitivity Vs = NAB/(kG) may not increase. The Assertion is therefore incorrect.", "misconception": "Ignoring the effect of increased resistance when adding more turns"}, {"option_key": "B", "hint": "Since the Assertion is incorrect (voltage sensitivity does not necessarily increase with N), options involving ''A is correct'' cannot be right.", "misconception": "Not analyzing the voltage sensitivity formula carefully"}, {"option_key": "C", "hint": "The Reason correctly states the formulas and the fact that G increases with N. This is physically accurate since more turns mean longer wire and greater resistance.", "misconception": "Thinking the Reason is wrong about resistance increasing with turns"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Cyclotron frequency\n(Q) Shunt resistance for ammeter\n(R) Series resistance for voltmeter\n(S) Current sensitivity of galvanometer\n\nColumn II:\n(1) NAB/k\n(2) V/Ig - G\n(3) qB/(2πm)\n(4) Ig·G/(I - Ig)", "explanation": "P-3: Cyclotron frequency f = qB/(2πm). Q-4: Shunt resistance S = Ig·G/(I - Ig) for converting galvanometer to ammeter. R-2: Series resistance R = V/Ig - G for converting galvanometer to voltmeter. S-1: Current sensitivity = NAB/k, which is the deflection per unit current in a galvanometer.", "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "ammeter-conversion", "voltmeter-conversion", "current-sensitivity", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-devices-29", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "P-3, Q-2, R-4, S-1", "is_correct": false}, {"key": "B", "text": "P-3, Q-4, R-2, S-1", "is_correct": true}, {"key": "C", "text": "P-4, Q-3, R-1, S-2", "is_correct": false}, {"key": "D", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps Q and R. The shunt resistance formula contains Ig·G/(I - Ig) which is (4), while the series resistance formula is V/Ig - G which is (2). So Q matches 4, not 2.", "misconception": "Swapping the ammeter and voltmeter conversion formulas"}, {"option_key": "C", "hint": "P-4 would match cyclotron frequency to the shunt formula, which is dimensionally inconsistent. Cyclotron frequency has units of Hz = 1/s, while Ig·G/(I-Ig) has units of Ω.", "misconception": "Not checking dimensional consistency of the formulas"}, {"option_key": "D", "hint": "P-1 matches cyclotron frequency with NAB/k, which is the current sensitivity formula. Cyclotron frequency f = qB/(2πm) matches with (3).", "misconception": "Confusing cyclotron frequency with galvanometer sensitivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Magnetic field inside a long solenoid\n(Q) Magnetic field of a toroid (inside)\n(R) Cyclotron maximum KE\n(S) Deflecting torque in a galvanometer\n\nColumn II:\n(1) NIAB\n(2) μ₀nI (n = turns per unit length)\n(3) q²B²R²/(2m)\n(4) μ₀NI/(2πr)", "explanation": "P-2: The magnetic field inside a long solenoid is B = μ₀nI, where n is the number of turns per unit length. Q-4: Inside a toroid, B = μ₀NI/(2πr), where N is total turns and r is the radius of the toroidal path. R-3: Maximum kinetic energy from a cyclotron is q²B²R²/(2m). S-1: The deflecting torque on the coil in a galvanometer is τ = NIAB.", "correct_answer": "A", "concept_tags": ["solenoid", "toroid", "cyclotron-energy", "galvanometer-torque", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-devices-30", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-4, R-3, S-1", "is_correct": true}, {"key": "B", "text": "P-4, Q-2, R-3, S-1", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": false}, {"key": "D", "text": "P-2, Q-1, R-3, S-4", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This swaps P and Q. The solenoid field B = μ₀nI uses turns per unit length (n), while the toroid field B = μ₀NI/(2πr) uses total turns N and has r in the denominator.", "misconception": "Confusing the solenoid and toroid magnetic field formulas"}, {"option_key": "C", "hint": "R-1 would match cyclotron KE with NIAB (torque). The cyclotron KE expression q²B²R²/(2m) is (3), and NIAB is the galvanometer torque (1).", "misconception": "Swapping the cyclotron energy and galvanometer torque expressions"}, {"option_key": "D", "hint": "Q-1 would match toroid field with NIAB, which is the torque expression for a galvanometer. The toroid field is μ₀NI/(2πr), which is (4).", "misconception": "Not distinguishing between the torque formula and the toroid field formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The figure of merit of a galvanometer is defined as the current required to produce a unit deflection in the galvanometer.", "explanation": "This statement is TRUE. The figure of merit of a galvanometer is defined as the current required to produce one unit (one division) of deflection. Mathematically, figure of merit = k/(NAB), where k is the torsional constant, N is the number of turns, A is the area, and B is the magnetic field. A smaller figure of merit indicates a more sensitive galvanometer.", "correct_answer": "A", "concept_tags": ["figure of merit", "galvanometer sensitivity"], "payload": {"question_id": "cuet-phy-mag-devices-31", "subtopic": "figure of merit", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "True", "is_correct": true}, {"key": "B", "value": "False", "is_correct": false}, {"key": "C", "value": "---", "is_correct": false}, {"key": "D", "value": "---", "is_correct": false}], "elimination_hints": ["Recall: figure of merit = I/θ = k/(NAB). It represents current per unit deflection.", "This is a standard textbook definition—figure of merit is the reciprocal of current sensitivity."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside a solenoid is uniform and parallel to the axis of the solenoid.", "explanation": "This statement is TRUE. Inside a long solenoid (ideal case), the magnetic field is uniform in both magnitude and direction. The field lines run parallel to the axis of the solenoid. This can be derived using Ampere''s law, which gives B = μ₀nI inside the solenoid (where n = N/L is the number of turns per unit length). Outside the solenoid, the field is approximately zero.", "correct_answer": "A", "concept_tags": ["solenoid", "uniform-magnetic-field", "field-direction"], "payload": {"question_id": "cuet-phy-mag-devices-32", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The field inside an ideal long solenoid is indeed uniform and axial. This is a standard result from Ampere''s law applied to a rectangular Amperian loop.", "misconception": "Confusing solenoid field with that of a bar magnet, where the field is non-uniform"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "An ideal voltmeter has zero resistance so that it does not draw any current from the circuit.", "explanation": "This statement is FALSE. An ideal voltmeter has infinite resistance (not zero resistance) so that it draws zero current from the circuit. Zero resistance is the characteristic of an ideal ammeter, not a voltmeter. A voltmeter with zero resistance would short-circuit the component across which it is connected.", "correct_answer": "B", "concept_tags": ["ideal voltmeter", "infinite resistance"], "payload": {"question_id": "cuet-phy-mag-devices-33", "subtopic": "conversion to voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "True", "is_correct": false}, {"key": "B", "value": "False", "is_correct": true}, {"key": "C", "value": "---", "is_correct": false}, {"key": "D", "value": "---", "is_correct": false}], "elimination_hints": ["Think about what happens if a voltmeter with zero resistance is connected in parallel—it would short-circuit the component.", "Zero resistance is the property of an ideal ammeter, not a voltmeter.", "For no current to flow through the voltmeter, its resistance must be as high as possible—ideally infinite."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A cyclotron can be used to accelerate electrons to high energies efficiently.", "explanation": "This statement is FALSE. A cyclotron cannot efficiently accelerate electrons because electrons have very small mass (9.1 x 10^-31 kg). Due to their low mass, electrons quickly reach relativistic speeds, at which point their mass increases significantly (relativistic mass increase). This causes the cyclotron frequency f = qB/(2πm) to decrease, and the particles go out of synchronization with the fixed-frequency oscillating electric field. This is a well-known limitation of the cyclotron.", "correct_answer": "B", "concept_tags": ["cyclotron", "electrons", "relativistic-effects", "limitation"], "payload": {"question_id": "cuet-phy-mag-devices-34", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small rest mass, so they reach relativistic speeds at relatively low energies. At relativistic speeds, the effective mass increases, changing the cyclotron frequency and causing loss of synchronization.", "misconception": "Thinking the cyclotron works for all charged particles without considering relativistic effects"}]}}]'::jsonb, 'deploy-2026-03-05-b09');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "To convert a galvanometer into a voltmeter, a ________ resistance is connected in ________ with the galvanometer.", "explanation": "To convert a galvanometer into a voltmeter, a high resistance is connected in series with it. The high series resistance ensures that the voltmeter draws negligible current from the circuit, thereby not disturbing the potential difference being measured. The total resistance of the voltmeter becomes R + G, where R >> G.", "correct_answer": "A", "concept_tags": ["voltmeter conversion", "series resistance"], "payload": {"question_id": "cuet-phy-mag-devices-35", "subtopic": "conversion to voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "high; series", "is_correct": true}, {"key": "B", "value": "low; series", "is_correct": false}, {"key": "C", "value": "high; parallel", "is_correct": false}, {"key": "D", "value": "low; parallel", "is_correct": false}], "elimination_hints": ["A voltmeter must have high resistance to avoid drawing significant current—this eliminates options with ''low'' resistance.", "A voltmeter measures potential difference across a component, so it must be connected in parallel with the component, but the internal conversion uses series connection.", "Low resistance in parallel describes an ammeter conversion (shunt), not a voltmeter conversion."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "In a moving coil galvanometer, a radial magnetic field is produced by using concave-shaped pole pieces and a _____ placed inside the coil.", "explanation": "A soft iron core is placed inside the coil of a moving coil galvanometer. The soft iron core, along with the concave-shaped (cylindrical) pole pieces of the permanent magnet, creates a radial magnetic field. In a radial field, the plane of the coil is always parallel to the magnetic field direction, so the torque τ = NIAB sin(90°) = NIAB for all angular positions. This ensures a linear relationship between the current and the deflection angle (θ ∝ I).", "correct_answer": "C", "concept_tags": ["moving-coil-galvanometer", "radial-field", "soft-iron-core", "construction"], "payload": {"question_id": "cuet-phy-mag-devices-36", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "Hard iron core", "is_correct": false}, {"key": "B", "text": "Copper cylinder", "is_correct": false}, {"key": "C", "text": "Soft iron core", "is_correct": true}, {"key": "D", "text": "Permanent magnet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Hard iron retains magnetism (used for permanent magnets) and is not suitable for the core. Soft iron is used because it has high permeability, low retentivity, and strengthens the radial field without permanent magnetization.", "misconception": "Confusing soft iron (high permeability, low retentivity) with hard iron (permanent magnets)"}, {"option_key": "B", "hint": "A copper cylinder is not used as the core. Copper is non-magnetic and would not help in creating a radial magnetic field. Soft iron''s high magnetic permeability is essential for concentrating field lines.", "misconception": "Confusing copper damping mechanism with the iron core"}, {"option_key": "D", "hint": "The permanent magnet provides the external magnetic field and is located outside the coil (as pole pieces). The core inside the coil is soft iron, which helps make this external field radial.", "misconception": "Confusing the location and role of the permanent magnet with the core"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "If the student first converts the galvanometer into an ammeter of range 0–2 A and then uses the same galvanometer (after removing the shunt) to make a voltmeter of range 0–50 V, what is the difference between the high resistance needed for the voltmeter and the shunt resistance needed for the ammeter?", "explanation": "For the ammeter: S = IgG/(I − Ig) = (0.004 × 25)/(2 − 0.004) = 0.1/1.996 ≈ 0.05 Ω. For the voltmeter: R = V/Ig − G = 50/0.004 − 25 = 12,500 − 25 = 12,475 Ω. Difference = 12,475 − 0.05 = 12,474.95 ≈ 12,475 Ω. The voltmeter resistance is overwhelmingly larger than the shunt resistance.", "correct_answer": "C", "concept_tags": ["ammeter conversion", "voltmeter conversion", "shunt resistance", "series resistance"], "payload": {"question_id": "cuet-phy-mag-devices-37", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "12,500 Ω", "is_correct": false}, {"key": "B", "value": "12,450 Ω", "is_correct": false}, {"key": "C", "value": "12,475 Ω (approx.)", "is_correct": true}, {"key": "D", "value": "12,525 Ω", "is_correct": false}], "elimination_hints": ["The shunt resistance is very small (~0.05 Ω), so the difference is approximately equal to the voltmeter''s series resistance itself.", "Voltmeter series resistance R = V/Ig − G = 12,500 − 25 = 12,475 Ω. The shunt is negligible in comparison.", "12,500 Ω would be the answer if G were zero—but we must subtract G = 25 Ω from the total."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A medical research lab uses a cyclotron to produce radioactive isotopes for PET (Positron Emission Tomography) scans. The cyclotron accelerates protons using a magnetic field of 2.0 T. The protons are extracted when they reach a radius of 0.4 m from the centre. If the cyclotron''s oscillating electric field operates at a fixed frequency, what is the frequency of the oscillating electric field, and what is the kinetic energy of the extracted protons? (Given: mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C)", "explanation": "The cyclotron frequency f = qB/(2πm) = (1.6 x 10^-19 x 2.0)/(2π x 1.67 x 10^-27) = 3.2 x 10^-19 / (1.049 x 10^-26) = 3.05 x 10^7 Hz ≈ 30.5 MHz. The maximum kinetic energy KE = q²B²R²/(2m) = (1.6 x 10^-19)² x (2.0)² x (0.4)² / (2 x 1.67 x 10^-27) = (2.56 x 10^-38 x 4 x 0.16) / (3.34 x 10^-27) = 1.638 x 10^-38 / 3.34 x 10^-27 = 4.9 x 10^-12 J. Converting: 4.9 x 10^-12 / 1.6 x 10^-13 ≈ 30.6 MeV. So the frequency is approximately 30.5 MHz and KE is approximately 30.6 MeV.", "correct_answer": "B", "concept_tags": ["cyclotron", "frequency", "kinetic-energy", "PET-scan", "medical-application", "numerical"], "payload": {"question_id": "cuet-phy-mag-devices-38", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "Frequency ≈ 15.2 MHz, KE ≈ 15 MeV", "is_correct": false}, {"key": "B", "text": "Frequency ≈ 30.5 MHz, KE ≈ 30.6 MeV", "is_correct": true}, {"key": "C", "text": "Frequency ≈ 30.5 MHz, KE ≈ 61 MeV", "is_correct": false}, {"key": "D", "text": "Frequency ≈ 61 MHz, KE ≈ 30.6 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "15.2 MHz is half the correct frequency. Check your calculation: f = qB/(2πm). With B = 2.0 T, the numerator is qB = 3.2 x 10^-19, not 1.6 x 10^-19. Ensure you use B = 2.0 T, not 1.0 T.", "misconception": "Using B = 1.0 T instead of 2.0 T in the frequency formula"}, {"option_key": "C", "hint": "The frequency is correct at 30.5 MHz, but 61 MeV is double the actual KE. Verify the factor of 2 in the denominator: KE = q²B²R²/(2m), not q²B²R²/m.", "misconception": "Forgetting the factor of 2 in the kinetic energy denominator"}, {"option_key": "D", "hint": "61 MHz is double the correct frequency. The formula is f = qB/(2πm), and 2π ≈ 6.28, not π ≈ 3.14. Using π instead of 2π would give the wrong answer.", "misconception": "Using π instead of 2π in the cyclotron frequency formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "easy", "question_text": "Arrange the following steps in the correct logical sequence for converting a galvanometer into an ammeter:", "explanation": "The correct sequence is: First, determine the galvanometer parameters Ig and G (step 2). Then, identify the desired ammeter range I (step 4). Next, use these values to calculate the required shunt resistance S = IgG/(I − Ig) (step 1). Finally, physically connect the shunt in parallel with the galvanometer (step 3). This sequence follows the logical flow from characterization to design to implementation.", "correct_answer": "C", "concept_tags": ["ammeter conversion", "shunt resistance", "logical sequence"], "payload": {"question_id": "cuet-phy-mag-devices-39", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "1, 2, 3, 4", "is_correct": false}, {"key": "B", "value": "4, 2, 1, 3", "is_correct": false}, {"key": "C", "value": "2, 4, 1, 3", "is_correct": true}, {"key": "D", "value": "2, 1, 4, 3", "is_correct": false}], "elimination_hints": ["You must know the galvanometer''s properties (Ig, G) before anything else—step 2 comes first.", "You cannot calculate the shunt (step 1) without knowing the desired range (step 4)—so step 4 must come before step 1.", "Physical connection (step 3) is always the last step—it comes after all calculations are done."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following events in the correct sequence that occurs when a current is passed through a moving coil galvanometer:", "explanation": "The correct sequence of events is: First, current flows through the coil in the radial magnetic field (step 3). This creates a deflecting torque on the coil (step 2, τ = NIAB). The coil then rotates and continues until the deflecting torque is balanced by the restoring torque of the spring (step 4, NIAB = kθ). Finally, the pointer shows the deflection on the scale (step 1). This follows the cause-and-effect chain from electrical input to mechanical output.", "correct_answer": "A", "concept_tags": ["galvanometer working", "deflecting torque", "restoring torque"], "payload": {"question_id": "cuet-phy-mag-devices-40", "subtopic": "working principle", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "3, 2, 4, 1", "is_correct": true}, {"key": "B", "value": "2, 3, 1, 4", "is_correct": false}, {"key": "C", "value": "3, 2, 1, 4", "is_correct": false}, {"key": "D", "value": "2, 3, 4, 1", "is_correct": false}], "elimination_hints": ["The process starts with current flowing through the coil—this is the input, so step 3 comes first.", "The pointer reading (step 1) is the final output—it must come last.", "Torque (step 2) is caused by the current (step 3), and the coil must rotate and reach equilibrium (step 4) before the reading is taken (step 1)."]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows four arrangements of two charges. In which arrangement is the electrostatic force between the charges repulsive?\n\n(A) +q ←→ −q\n(B) +q ←→ +q\n(C) −q ←→ +q\n(D) −q ←→ −2q (with one charge having larger magnitude)", "explanation": "Repulsive force occurs between like charges. Arrangement B (+q and +q) has two positive charges — they repel. Arrangement D (−q and −2q) also has like charges (both negative) — they also repel. But among the options, B is the straightforward like-charge case. Arrangements A and C have unlike charges and attract.", "correct_answer": "B", "concept_tags": ["like-charges", "repulsion", "attraction"], "payload": {"question_id": "cuet-phy-elec-coulomb-41", "subtopic": "Nature of electrostatic force", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Arrangement A only", "is_correct": false}, {"key": "B", "text": "Arrangements B and D", "is_correct": true}, {"key": "C", "text": "Arrangement C only", "is_correct": false}, {"key": "D", "text": "All four arrangements", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Arrangement A has +q and −q (unlike charges) — they attract, not repel.", "misconception": "Confusing attraction with repulsion for unlike charges"}, {"option_key": "C", "hint": "Arrangement C has −q and +q (unlike charges) — this is identical in nature to A, both attract.", "misconception": "Not recognising that the order doesn''t matter — unlike charges always attract"}, {"option_key": "D", "hint": "Arrangements A and C have unlike charges, which attract — not all four are repulsive.", "misconception": "Thinking all charged bodies repel"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a graph of electrostatic force F versus distance r between two point charges. Which curve correctly represents Coulomb''s law?\n\nCurve P: F decreases linearly with r\nCurve Q: F decreases as 1/r²  (hyperbolic)\nCurve R: F decreases as 1/r (slower hyperbola)\nCurve S: F remains constant", "explanation": "Coulomb''s law states F = kq₁q₂/r², so F ∝ 1/r². This is represented by Curve Q — a steep hyperbolic decay. At small r, the force is very large; it drops rapidly and approaches zero at large r. The 1/r² curve is steeper than 1/r at small distances.", "correct_answer": "A", "concept_tags": ["inverse-square-law", "graphical-representation", "force-distance"], "payload": {"question_id": "cuet-phy-elec-coulomb-42", "subtopic": "Coulomb''s law graphical analysis", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Curve Q", "is_correct": true}, {"key": "B", "text": "Curve P", "is_correct": false}, {"key": "C", "text": "Curve R", "is_correct": false}, {"key": "D", "text": "Curve S", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Curve P shows a linear decrease, meaning F ∝ (constant − r). Coulomb''s law is not linear — it''s inverse square.", "misconception": "Thinking force decreases linearly with distance"}, {"option_key": "C", "hint": "Curve R (1/r) represents electric potential V = kq/r, not force. Force falls faster (as 1/r²).", "misconception": "Confusing force (1/r²) with potential (1/r)"}, {"option_key": "D", "hint": "Curve S (constant force) would mean force doesn''t depend on distance, contradicting Coulomb''s law completely.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The figure shows four charges placed at the corners of a square of side a: +q at A (top-left), +q at B (top-right), −q at C (bottom-right), −q at D (bottom-left). What is the direction of the net force on the charge at A?", "explanation": "Forces on +q at A: From +q at B (distance a, repulsive → pushes A leftward). From −q at C (distance a√2, attractive → pulls A toward C, i.e., diagonally toward bottom-right). From −q at D (distance a, attractive → pulls A downward). The leftward push from B and downward pull from D combine. Adding the diagonal pull toward C, the net force points approximately toward D (downward and slightly right), i.e., parallel to the side AD directed downward.", "correct_answer": "C", "concept_tags": ["vector-addition", "square-configuration", "net-force"], "payload": {"question_id": "cuet-phy-elec-coulomb-43", "subtopic": "Superposition of forces", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Horizontally toward B", "is_correct": false}, {"key": "B", "text": "Along the diagonal AC, toward C", "is_correct": false}, {"key": "C", "text": "Parallel to AD, directed from A toward D", "is_correct": true}, {"key": "D", "text": "Zero — forces cancel by symmetry", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The force from +q at B is repulsive (pushes A away from B, i.e., leftward), not toward B.", "misconception": "Confusing attraction and repulsion directions"}, {"option_key": "B", "hint": "While there is a component toward C, the forces from B and D also contribute. The net direction is along AD, not along the diagonal.", "misconception": "Considering only the diagonal force and ignoring edge forces"}, {"option_key": "D", "hint": "The configuration is NOT symmetric about charge A — there''s +q on one side and −q on the other. Forces don''t cancel.", "misconception": "Incorrectly assuming symmetry at a corner of a non-uniform charge distribution"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The figure shows a log-log plot (log F vs log r) for the electrostatic force between two point charges. The graph is a straight line with slope −2 and y-intercept log(kq₁q₂). If the experimental data shows a slope of −2.05 ± 0.03, what can be concluded?", "explanation": "Taking log of F = kq₁q₂/rⁿ gives log F = log(kq₁q₂) − n × log r. A log-log plot gives a straight line with slope −n. The theoretical value is n = 2 (inverse square law). The experimental slope of −2.05 ± 0.03 includes n = 2 within the error range (2.05 − 0.03 = 2.02 and 2.05 + 0.03 = 2.08), so the data is consistent with the inverse square law within experimental uncertainty.", "correct_answer": "D", "concept_tags": ["log-log-plot", "experimental-verification", "inverse-square"], "payload": {"question_id": "cuet-phy-elec-coulomb-44", "subtopic": "Experimental verification of Coulomb''s law", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Coulomb''s law is definitively disproved", "is_correct": false}, {"key": "B", "text": "The force follows an inverse cube law", "is_correct": false}, {"key": "C", "text": "The experiment has no errors", "is_correct": false}, {"key": "D", "text": "The data is consistent with Coulomb''s inverse square law within experimental uncertainty", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A slope of −2.05 ± 0.03 is very close to −2 and includes −2 within 2σ. Experimental uncertainty must be considered before claiming a law is disproved.", "misconception": "Ignoring experimental uncertainty when comparing with theory"}, {"option_key": "B", "hint": "An inverse cube law would give slope −3, which is far outside the measured range of −2.05 ± 0.03.", "misconception": "Confusing the measured slope with a completely different power law"}, {"option_key": "C", "hint": "Every experiment has some uncertainty. The ±0.03 explicitly states the error range.", "misconception": "Thinking a small deviation means zero error rather than acknowledging uncertainty"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The electrostatic force between two point charges is a central force.\nReason (R): The force acts along the line joining the two charges and depends only on the distance between them.", "explanation": "A central force is one that acts along the line joining two particles and depends only on the scalar distance between them. Coulomb''s force F = kq₁q₂r̂/r² satisfies both conditions — it acts along r̂ (the unit vector from one charge to the other) and depends only on r. The reason correctly states both defining properties of a central force, making it the correct explanation of the assertion.", "correct_answer": "A", "concept_tags": ["central-force", "coulomb-law", "force-properties"], "payload": {"question_id": "cuet-phy-elec-coulomb-45", "subtopic": "Properties of Coulomb''s force", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The two properties mentioned in R (acts along joining line + depends only on distance) are the defining properties of a central force. R directly defines and explains why A is true.", "misconception": "Not recognising that R states the exact definition of a central force"}, {"option_key": "C", "hint": "R is a correct statement — Coulomb''s force does indeed act along the line joining charges and depends only on r.", "misconception": null}, {"option_key": "D", "hint": "A is correct — Coulomb''s force is indeed a central force, which is why angular momentum is conserved in classical electron orbits.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A sensitive gold-leaf electroscope can detect charge quantization at macroscopic scales.\nReason (R): The elementary charge e = 1.6 × 10⁻¹⁹ C is extremely small compared to charges typically encountered in daily life.", "explanation": "A is FALSE: at macroscopic scales, charges are so large (of order μC or more) that the discrete nature (quantization) of charge is not observable — charge appears continuous. R is TRUE: e is indeed extremely small compared to macroscopic charges, which is precisely why quantization is undetectable at large scales. Since A is incorrect and R is correct, the answer is D.", "correct_answer": "D", "concept_tags": ["quantization", "macroscopic-charge", "gold-leaf-electroscope"], "payload": {"question_id": "cuet-phy-elec-coulomb-46", "subtopic": "Quantization of charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The assertion is incorrect — quantization cannot be detected at macroscopic scales because the elementary charge is too small relative to everyday charges.", "misconception": "Thinking quantization is easily observable with a gold-leaf electroscope"}, {"option_key": "B", "hint": "A is false, not true. A gold-leaf electroscope cannot detect individual electron charges.", "misconception": null}, {"option_key": "C", "hint": "R is actually correct — e = 1.6 × 10⁻¹⁹ C is indeed extremely small compared to typical macroscopic charges.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Coulomb''s force between two charges obeys Newton''s third law.\nReason (R): The force exerted by charge q₁ on q₂ is equal in magnitude and opposite in direction to the force exerted by q₂ on q₁.", "explanation": "Both A and R are correct. F₁₂ = kq₁q₂r̂₁₂/r² and F₂₁ = kq₁q₂r̂₂₁/r² = −F₁₂. This satisfies Newton''s third law (action = −reaction). R correctly states this property and directly explains A.", "correct_answer": "A", "concept_tags": ["newton-third-law", "action-reaction", "coulomb-law"], "payload": {"question_id": "cuet-phy-elec-coulomb-47", "subtopic": "Properties of Coulomb''s force", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R is the exact statement of Newton''s third law applied to Coulomb forces. Since A says Coulomb''s force obeys Newton''s third law, R is by definition the correct explanation.", "misconception": "Not seeing that R is just the restatement of Newton''s third law for this specific case"}, {"option_key": "C", "hint": "R is factually correct — by Coulomb''s law, F₁₂ = −F₂₁ always holds.", "misconception": null}, {"option_key": "D", "hint": "A is correct — Coulomb''s force is a conservative, central force that obeys Newton''s third law.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Coulomb''s law accurately predicts the force between two charged bodies of any shape and size.\nReason (R): Coulomb''s law is derived for point charges and works accurately only when the size of the charged bodies is much smaller than the distance between them.", "explanation": "A is FALSE: Coulomb''s law in its standard form F = kq₁q₂/r² is strictly valid only for point charges (or when bodies are very small compared to separation). For extended bodies, charge distribution matters and the simple formula is inadequate. R is TRUE: it correctly states the limitation. Since A is wrong and R is right, the answer is D.", "correct_answer": "D", "concept_tags": ["coulomb-law-limitations", "point-charge-approximation"], "payload": {"question_id": "cuet-phy-elec-coulomb-48", "subtopic": "Validity conditions of Coulomb''s law", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A is false — Coulomb''s law does not work for bodies of any shape/size. For large or close conductors, charge redistribution invalidates the point-charge formula.", "misconception": "Thinking Coulomb''s law applies universally to all shapes"}, {"option_key": "B", "hint": "A is false, so this option cannot be correct.", "misconception": null}, {"option_key": "C", "hint": "R is factually correct — it accurately describes the point-charge requirement of Coulomb''s law.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electric charge is an additive quantity — the total charge of a system is the algebraic sum of all individual charges.", "explanation": "This is TRUE. Additivity of charge means the total charge of a system equals the algebraic (not absolute) sum of all charges. For example, if a system has charges +5 μC and −3 μC, the total charge is +2 μC. This property, along with conservation and quantization, is a fundamental property of electric charge.", "correct_answer": "A", "concept_tags": ["additivity", "charge-properties", "algebraic-sum"], "payload": {"question_id": "cuet-phy-elec-coulomb-49", "subtopic": "Properties of electric charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Additivity of charge is a well-established property. Unlike some quantities (like mass in relativity), charge adds algebraically in all situations.", "misconception": "Confusing additivity of charge with non-additive quantities"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The electrostatic force between two charges is independent of the presence of other charges nearby (superposition principle).", "explanation": "This is TRUE. The superposition principle states that the force between any two charges is given by Coulomb''s law regardless of the presence of other charges. The net force on a charge is the vector sum of individual pair-wise forces. Each pair interaction is unaffected by the existence of third charges.", "correct_answer": "A", "concept_tags": ["superposition", "independent-interaction", "pair-force"], "payload": {"question_id": "cuet-phy-elec-coulomb-50", "subtopic": "Superposition principle", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The superposition principle is a cornerstone of classical electrostatics. The Coulomb force between any pair depends only on those two charges and their separation.", "misconception": "Thinking nearby charges modify the force between a specific pair"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The force between two point charges depends on the nature of the medium between them — it decreases when a dielectric is placed between them but increases when they are in vacuum.", "explanation": "This is partially misleading but essentially FALSE as stated. The statement implies the force ''increases in vacuum'' as if vacuum makes it stronger than some baseline — but vacuum IS the reference (maximum force). The force in any medium is F/K where K ≥ 1. The statement''s implication that force ''increases'' in vacuum is incorrect framing. The correct statement: force is maximum in vacuum and decreases in any dielectric medium.", "correct_answer": "B", "concept_tags": ["dielectric-effect", "medium-dependence", "vacuum"], "payload": {"question_id": "cuet-phy-elec-coulomb-51", "subtopic": "Coulomb''s law in different media", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The phrasing ''increases in vacuum'' is misleading. Force is maximum in vacuum — it doesn''t ''increase'' because vacuum is already the reference state (K=1). Any medium only reduces the force.", "misconception": "Thinking vacuum actively increases the force rather than being the baseline"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Quarks, which have charges of ±e/3 and ±2e/3, violate the principle of quantization of electric charge.", "explanation": "This is FALSE. Quarks do carry fractional charges (e/3 and 2e/3), but they never exist as free particles — they are always confined within hadrons (protons, neutrons, mesons) due to quark confinement. The principle of quantization of charge states that all freely observed charges are integral multiples of e. Quarks do not violate this because they are never observed in isolation.", "correct_answer": "B", "concept_tags": ["quarks", "quantization", "confinement"], "payload": {"question_id": "cuet-phy-elec-coulomb-52", "subtopic": "Quantization of charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Quarks are always confined inside hadrons and never exist freely. The quantization principle applies to freely observable charge, not to quarks inside composite particles.", "misconception": "Thinking quark charges violate quantization because they are fractional"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the charging method in Column I with its key characteristic in Column II:\n\nColumn I:\nA. Charging by friction\nB. Charging by conduction\nC. Charging by induction\nD. Charging by a Van de Graaff generator\n\nColumn II:\n1. Charge accumulation on a hollow sphere using a belt\n2. Both bodies acquire equal and opposite charges\n3. The charged body transfers charge to the uncharged body on contact\n4. The charged body induces charge separation without contact", "explanation": "Friction (A) involves rubbing two bodies — both acquire equal and opposite charges → A-2. Conduction (B) involves touching a charged body to an uncharged one — charge flows on contact → B-3. Induction (C) involves bringing a charged body near an uncharged conductor without contact → C-4. Van de Graaff generator (D) uses a moving belt to accumulate charge on a hollow metal sphere → D-1.", "correct_answer": "C", "concept_tags": ["charging-methods", "friction", "conduction", "induction"], "payload": {"question_id": "cuet-phy-elec-coulomb-53", "subtopic": "Methods of charging", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "A-3, B-2, C-4, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "C", "text": "A-2, B-3, C-4, D-1", "is_correct": true}, {"key": "D", "text": "A-4, B-3, C-2, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns ''charge transfer on contact'' (3) to friction and ''equal and opposite charges'' (2) to conduction. In friction, both bodies get equal opposite charges; conduction involves contact transfer.", "misconception": "Swapping friction and conduction characteristics"}, {"option_key": "B", "hint": "This assigns ''no contact'' (4) to conduction, but conduction requires physical contact.", "misconception": "Confusing conduction (contact required) with induction (no contact)"}, {"option_key": "D", "hint": "This assigns ''no contact'' (4) to friction, but friction requires vigorous rubbing (contact).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the physical situation in Column I with the correct force expression in Column II:\n\nColumn I:\nA. Two charges q in vacuum at distance d\nB. Two charges q in medium (K=4) at distance d\nC. Two charges q in vacuum at distance 2d\nD. Charges 2q and q in vacuum at distance d\n\nColumn II:\n1. kq²/(4d²)\n2. 2kq²/d²\n3. kq²/(4d²)\n4. kq²/d²", "explanation": "A: F = kq²/d² → A-4. B: F = kq²/(Kd²) = kq²/(4d²) → B-1 (or B-3, since items 1 and 3 are identical). C: F = kq²/(2d)² = kq²/(4d²) → C-3 (or C-1). D: F = k(2q)(q)/d² = 2kq²/d² → D-2. Note: items 1 and 3 have the same expression, so B and C both map to kq²/(4d²).", "correct_answer": "B", "concept_tags": ["coulomb-law-variations", "dielectric", "distance-scaling"], "payload": {"question_id": "cuet-phy-elec-coulomb-54", "subtopic": "Coulomb''s law applications", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "B", "text": "A-4, B-1, C-3, D-2", "is_correct": true}, {"key": "C", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "D", "text": "A-4, B-3, C-2, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns 2kq²/d² to situation B (medium K=4), but a medium reduces the force, so B cannot give the largest force expression.", "misconception": "Thinking a dielectric increases the force"}, {"option_key": "C", "hint": "This assigns kq²/d² (full vacuum force) to two charges q in vacuum at 2d — but doubling distance reduces force by 4.", "misconception": "Ignoring the effect of doubling the distance"}, {"option_key": "D", "hint": "This maps D (charges 2q and q) to kq²/(4d²), but the product 2q×q = 2q² gives 2kq²/d², not kq²/4d².", "misconception": "Not computing the charge product correctly"}]}}]'::jsonb, 'deploy-2026-03-05-b09');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The minimum charge that can exist independently in nature is called the _____ charge, and its value is approximately _____.", "explanation": "The minimum independently existing charge is the elementary charge (e), with value approximately 1.6 × 10⁻¹⁹ C. This was first accurately measured by Robert Millikan in his oil-drop experiment (1909). All observable charges are integral multiples of this fundamental unit.", "correct_answer": "D", "concept_tags": ["elementary-charge", "millikan-experiment"], "payload": {"question_id": "cuet-phy-elec-coulomb-55", "subtopic": "Quantization of charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "unit; 1 coulomb", "is_correct": false}, {"key": "B", "text": "fractional; 1.6 × 10⁻²⁰ C", "is_correct": false}, {"key": "C", "text": "atomic; 9.1 × 10⁻³¹ kg", "is_correct": false}, {"key": "D", "text": "elementary; 1.6 × 10⁻¹⁹ C", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1 coulomb is a macroscopic unit of charge (≈6.25 × 10¹⁸ electron charges), far too large to be the minimum charge.", "misconception": "Confusing the SI unit with the fundamental minimum"}, {"option_key": "B", "hint": "1.6 × 10⁻²⁰ C is ten times smaller than the actual elementary charge. Also, charge is not called ''fractional charge''.", "misconception": "Incorrect value of elementary charge"}, {"option_key": "C", "hint": "9.1 × 10⁻³¹ kg is the mass of an electron, not a charge. The units are wrong (kg vs C).", "misconception": "Confusing electron mass with electron charge"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The electrostatic force between two charges of 1 C each placed 1 m apart in vacuum is approximately _____ N.", "explanation": "F = kq₁q₂/r² = 9 × 10⁹ × 1 × 1 / 1² = 9 × 10⁹ N. This enormous force (about 9 billion newtons!) shows that 1 C is an extremely large amount of charge. For reference, this force is roughly equal to the weight of one million tonnes.", "correct_answer": "C", "concept_tags": ["coulomb-law", "numerical", "force-magnitude"], "payload": {"question_id": "cuet-phy-elec-coulomb-56", "subtopic": "Magnitude of electrostatic force", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "9 × 10⁶", "is_correct": false}, {"key": "B", "text": "9 × 10¹²", "is_correct": false}, {"key": "C", "text": "9 × 10⁹", "is_correct": true}, {"key": "D", "text": "1.6 × 10⁻¹⁹", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "9 × 10⁶ is three orders of magnitude too small. The Coulomb constant k = 9 × 10⁹, and with unit charges at 1 m, F = k directly.", "misconception": "Using wrong exponent for Coulomb''s constant"}, {"option_key": "B", "hint": "9 × 10¹² is three orders too large. Since both charges are 1 C and distance is 1 m, F simply equals k = 9 × 10⁹.", "misconception": "Adding extra factors beyond the formula"}, {"option_key": "D", "hint": "1.6 × 10⁻¹⁹ is the value of the elementary charge in coulombs, not a force value.", "misconception": "Confusing charge with force"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A student performs Millikan''s oil drop experiment. She observes a tiny oil drop of mass 4.9 × 10⁻¹⁵ kg suspended motionless between two horizontal plates separated by 2 cm, with a potential difference of 980 V applied between them. Taking g = 9.8 m/s², the charge on the oil drop is approximately:", "explanation": "For the drop to be stationary, the upward electric force must balance gravity: qE = mg. Electric field E = V/d = 980/0.02 = 49000 V/m. Charge q = mg/E = (4.9 × 10⁻¹⁵ × 9.8) / 49000 = 48.02 × 10⁻¹⁵ / 49000 = 9.8 × 10⁻¹⁹ C. This is approximately 6e (6 × 1.6 × 10⁻¹⁹ = 9.6 × 10⁻¹⁹ C), confirming quantization — the charge is an integer multiple of e.", "correct_answer": "A", "concept_tags": ["millikan-experiment", "charge-quantization", "force-balance"], "payload": {"question_id": "cuet-phy-elec-coulomb-57", "subtopic": "Millikan''s oil drop experiment", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "9.8 × 10⁻¹⁹ C (≈ 6e)", "is_correct": true}, {"key": "B", "text": "1.6 × 10⁻¹⁹ C (= e)", "is_correct": false}, {"key": "C", "text": "4.9 × 10⁻¹⁹ C (≈ 3e)", "is_correct": false}, {"key": "D", "text": "3.2 × 10⁻¹⁸ C (= 20e)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1.6 × 10⁻¹⁹ C (single electron charge) would require a much lighter drop or much stronger field to achieve equilibrium with the given values.", "misconception": "Assuming the drop carries only one electron charge without calculating"}, {"option_key": "C", "hint": "4.9 × 10⁻¹⁹ is half the correct answer — likely from a factor-of-2 error in the calculation (perhaps using d = 4 cm instead of 2 cm).", "misconception": "Error in the plate separation value"}, {"option_key": "D", "hint": "3.2 × 10⁻¹⁸ is about 3× too large — possibly from using E = V (not V/d) or a unit conversion error.", "misconception": "Forgetting to divide voltage by distance to get electric field"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "In an advanced electrostatics lab, two identical insulating spheres A and B carry charges +6Q and −2Q respectively. They are touched together, separated, and then sphere B is touched to an identical uncharged sphere C. After all separations, the charges on A, B, and C respectively are:", "explanation": "Step 1: A (+6Q) and B (−2Q) touch → total = 4Q, each gets +2Q. After separation: A = +2Q, B = +2Q. Step 2: B (+2Q) touches C (0) → total = 2Q, each gets +Q. After separation: B = +Q, C = +Q. Final: A = +2Q, B = +Q, C = +Q.", "correct_answer": "D", "concept_tags": ["charge-sharing", "multiple-steps", "conductors"], "payload": {"question_id": "cuet-phy-elec-coulomb-58", "subtopic": "Charge redistribution", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "+2Q, +2Q, 0", "is_correct": false}, {"key": "B", "text": "+3Q, +Q/2, +Q/2", "is_correct": false}, {"key": "C", "text": "+4Q/3, +4Q/3, +4Q/3", "is_correct": false}, {"key": "D", "text": "+2Q, +Q, +Q", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This only accounts for step 1 (A and B sharing charge) but ignores step 2 (B touching C).", "misconception": "Forgetting the second touching step"}, {"option_key": "B", "hint": "+3Q total ≠ 4Q total. The total charge must be conserved at +6Q + (−2Q) = +4Q throughout.", "misconception": "Arithmetic error in charge conservation"}, {"option_key": "C", "hint": "This assumes all three spheres share charge equally, but A was separated before B touched C. A doesn''t participate in the second sharing.", "misconception": "Assuming all three spheres share charge simultaneously"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps of charging a metal sphere by induction in the correct sequence:\n\n1. Ground the sphere (connect to earth)\n2. Bring a positively charged rod near the sphere (without touching)\n3. Remove the grounding connection\n4. Remove the charged rod\n5. Negative charge remains on the sphere", "explanation": "Correct sequence: First bring the charged rod near (2) → this induces charge separation. Then ground the sphere (1) → positive charges flow to earth, leaving excess negative. Remove ground (3) → excess negative charge is trapped. Remove the rod (4) → negative charge redistributes uniformly. Result: sphere is negatively charged (5).", "correct_answer": "C", "concept_tags": ["induction-charging", "sequence", "grounding"], "payload": {"question_id": "cuet-phy-elec-coulomb-59", "subtopic": "Charging by induction", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "1 → 2 → 3 → 4 → 5", "is_correct": false}, {"key": "B", "text": "2 → 3 → 1 → 4 → 5", "is_correct": false}, {"key": "C", "text": "2 → 1 → 3 → 4 → 5", "is_correct": true}, {"key": "D", "text": "1 → 2 → 4 → 3 → 5", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Grounding first (step 1) without the charged rod nearby has no effect — there''s no induced charge to drain. The rod must be brought close first.", "misconception": "Grounding before bringing the inducing charge"}, {"option_key": "B", "hint": "Removing ground (step 3) before connecting it (step 1) is illogical. You must ground first, then remove the ground.", "misconception": "Mixing up the order of grounding and ungrounding"}, {"option_key": "D", "hint": "Removing the rod (step 4) before removing the ground (step 3) would allow the trapped negative charge to flow back to earth, leaving the sphere uncharged.", "misconception": "Not realising that the ground must be removed BEFORE the rod"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following discoveries/developments in the history of electrostatics in chronological order:\n\n1. Millikan''s oil drop experiment (precise measurement of e)\n2. Coulomb''s torsion balance experiment\n3. Benjamin Franklin''s kite experiment\n4. Discovery of the electron by J.J. Thomson", "explanation": "Chronological order: Benjamin Franklin''s kite experiment (1752) → Coulomb''s torsion balance (1785) → J.J. Thomson discovers the electron (1897) → Millikan''s oil drop experiment (1909). So the sequence is 3 → 2 → 4 → 1.", "correct_answer": "B", "concept_tags": ["history-of-physics", "chronological-order", "electrostatics"], "payload": {"question_id": "cuet-phy-elec-coulomb-60", "subtopic": "Historical development", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "2 → 3 → 4 → 1", "is_correct": false}, {"key": "B", "text": "3 → 2 → 4 → 1", "is_correct": true}, {"key": "C", "text": "3 → 2 → 1 → 4", "is_correct": false}, {"key": "D", "text": "1 → 4 → 2 → 3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s experiment (1785) came after Franklin''s (1752), not before. Franklin predated Coulomb by about 33 years.", "misconception": "Placing Coulomb before Franklin"}, {"option_key": "C", "hint": "Millikan (1909) came after Thomson (1897), not before. Millikan measured the charge of the electron that Thomson had discovered.", "misconception": "Thinking Millikan''s experiment preceded Thomson''s discovery of the electron"}, {"option_key": "D", "hint": "This puts the most recent (Millikan, 1909) first and the earliest (Franklin, 1752) last — completely reversed chronology.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Bohr''s model, the angular momentum of an electron in the nth orbit of a hydrogen atom is:", "explanation": "Bohr''s quantization postulate states that the angular momentum of an electron in a stationary orbit is an integral multiple of h/2π. That is, L = mvr = nh/2π, where n is the principal quantum number (n = 1, 2, 3, ...). This was a key postulate that explained the stability of atoms.", "correct_answer": "A", "concept_tags": ["bohr-model", "angular-momentum-quantization", "bohr-postulate"], "payload": {"question_id": "cuet-phy-atom-bohr-01", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "remember", "options": [{"key": "A", "text": "nh/2π", "is_correct": true}, {"key": "B", "text": "nh/π", "is_correct": false}, {"key": "C", "text": "n²h/2π", "is_correct": false}, {"key": "D", "text": "nh/4π", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is twice the correct value. Bohr''s quantization condition has 2π in the denominator, not π.", "misconception": "Forgetting the factor of 2 in 2π"}, {"option_key": "C", "hint": "Angular momentum is proportional to n, not n². The n² dependence applies to orbital radius, not angular momentum.", "misconception": "Confusing radius formula (n² dependence) with angular momentum formula (n dependence)"}, {"option_key": "D", "hint": "The denominator is 2π (from ħ = h/2π), not 4π. The factor 4π appears in Coulomb''s law, not in the angular momentum quantization.", "misconception": "Mixing up constants from different formulas"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The radius of the first Bohr orbit of hydrogen atom (Bohr radius) is approximately:", "explanation": "The Bohr radius a₀ is the radius of the first orbit (n = 1) of the hydrogen atom (Z = 1). Its value is a₀ = ε₀h²/(πme²) ≈ 0.529 Å = 0.529 × 10⁻¹⁰ m. This is a fundamental constant used as the unit of length in atomic physics.", "correct_answer": "B", "concept_tags": ["bohr-radius", "hydrogen-atom", "first-orbit"], "payload": {"question_id": "cuet-phy-atom-bohr-02", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "remember", "options": [{"key": "A", "text": "0.329 Å", "is_correct": false}, {"key": "B", "text": "0.529 Å", "is_correct": true}, {"key": "C", "text": "1.058 Å", "is_correct": false}, {"key": "D", "text": "2.116 Å", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This value is not standard. The Bohr radius is a well-known constant equal to 0.529 Å.", "misconception": "Recalling an incorrect numerical value"}, {"option_key": "C", "hint": "1.058 Å = 2 × 0.529 Å. This would be the radius of the first orbit for a hypothetical scenario, not the standard Bohr radius.", "misconception": "Doubling the Bohr radius inadvertently"}, {"option_key": "D", "hint": "2.116 Å = 4 × 0.529 Å = 0.529 × 2². This is actually the radius of the second Bohr orbit (n = 2) for hydrogen.", "misconception": "Confusing the second orbit radius with the first orbit radius"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In Rutherford''s alpha-particle scattering experiment, most of the alpha particles pass through the gold foil without any deflection because:", "explanation": "Rutherford''s experiment showed that most alpha particles passed straight through the gold foil with little or no deflection. This is because most of the atom is empty space — the nucleus occupies an extremely small fraction (about 10⁻¹⁵ m in diameter compared to 10⁻¹⁰ m for the atom). Hence, most particles never come close to the nucleus.", "correct_answer": "C", "concept_tags": ["rutherford-scattering", "nuclear-model", "alpha-particle"], "payload": {"question_id": "cuet-phy-atom-bohr-03", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "understand", "options": [{"key": "A", "text": "The nucleus has no charge", "is_correct": false}, {"key": "B", "text": "Alpha particles are much heavier than gold atoms", "is_correct": false}, {"key": "C", "text": "Most of the space inside an atom is empty", "is_correct": true}, {"key": "D", "text": "Alpha particles have very high kinetic energy", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The gold nucleus has a charge of +79e. In fact, it is the nuclear charge that causes the deflection of those alpha particles that pass close to the nucleus.", "misconception": "Believing the nucleus is electrically neutral"}, {"option_key": "B", "hint": "Gold atoms (mass number 197) are actually much heavier than alpha particles (mass number 4). This is why alpha particles bounce back when they hit the nucleus head-on.", "misconception": "Reversing the relative masses of alpha particles and gold atoms"}, {"option_key": "D", "hint": "While alpha particles do have high kinetic energy, this alone does not explain why most pass undeflected. The reason is the emptiness of the atom.", "misconception": "Attributing undeflected passage to kinetic energy rather than atomic structure"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The Lyman series of the hydrogen spectrum lies in which region of the electromagnetic spectrum?", "explanation": "The Lyman series corresponds to transitions from higher energy levels (n₂ = 2, 3, 4, ...) to the ground state (n₁ = 1). These transitions involve the largest energy differences and produce photons in the ultraviolet region. The Balmer series lies in the visible region, while Paschen, Brackett, and Pfund series lie in the infrared region.", "correct_answer": "D", "concept_tags": ["lyman-series", "hydrogen-spectrum", "ultraviolet"], "payload": {"question_id": "cuet-phy-atom-bohr-04", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "remember", "options": [{"key": "A", "text": "Visible region", "is_correct": false}, {"key": "B", "text": "Infrared region", "is_correct": false}, {"key": "C", "text": "Microwave region", "is_correct": false}, {"key": "D", "text": "Ultraviolet region", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The visible region corresponds to the Balmer series (transitions to n = 2), not the Lyman series.", "misconception": "Confusing Lyman series with Balmer series"}, {"option_key": "B", "hint": "The infrared region corresponds to the Paschen (n₁ = 3), Brackett (n₁ = 4), and Pfund (n₁ = 5) series.", "misconception": "Confusing Lyman series with Paschen/Brackett/Pfund series"}, {"option_key": "C", "hint": "Microwave radiation has much lower energy than the transitions in the hydrogen atom spectral series.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The energy of an electron in the third Bohr orbit of hydrogen atom is:", "explanation": "The energy of an electron in the nth orbit of a hydrogen-like atom is Eₙ = −13.6Z²/n² eV. For hydrogen (Z = 1) in the third orbit (n = 3): E₃ = −13.6 × 1²/3² = −13.6/9 ≈ −1.51 eV.", "correct_answer": "B", "concept_tags": ["energy-levels", "hydrogen-atom", "bohr-model"], "payload": {"question_id": "cuet-phy-atom-bohr-05", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "−3.40 eV", "is_correct": false}, {"key": "B", "text": "−1.51 eV", "is_correct": true}, {"key": "C", "text": "−0.85 eV", "is_correct": false}, {"key": "D", "text": "−13.6 eV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "−3.40 eV = −13.6/4 = −13.6/2². This corresponds to n = 2 (second orbit), not n = 3.", "misconception": "Using n = 2 instead of n = 3"}, {"option_key": "C", "hint": "−0.85 eV = −13.6/16 = −13.6/4². This corresponds to n = 4 (fourth orbit), not n = 3.", "misconception": "Using n = 4 instead of n = 3"}, {"option_key": "D", "hint": "−13.6 eV is the energy of the ground state (n = 1). For n = 3, you must divide by n² = 9.", "misconception": "Forgetting to divide by n²"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the radii of the first three Bohr orbits of hydrogen atom is:", "explanation": "The radius of the nth Bohr orbit is rₙ = n²a₀/Z. For hydrogen (Z = 1): r₁ = a₀, r₂ = 4a₀, r₃ = 9a₀. Therefore, r₁ : r₂ : r₃ = 1 : 4 : 9, which follows the n² dependence.", "correct_answer": "C", "concept_tags": ["bohr-radius", "orbit-radius", "n-squared-dependence"], "payload": {"question_id": "cuet-phy-atom-bohr-06", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "1 : 2 : 3", "is_correct": false}, {"key": "B", "text": "1 : 8 : 27", "is_correct": false}, {"key": "C", "text": "1 : 4 : 9", "is_correct": true}, {"key": "D", "text": "1 : 1/4 : 1/9", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The ratio 1:2:3 corresponds to a linear (n) dependence. Bohr orbit radius depends on n², not n.", "misconception": "Assuming radius is proportional to n instead of n²"}, {"option_key": "B", "hint": "The ratio 1:8:27 corresponds to an n³ dependence. The radius depends on n², not n³.", "misconception": "Using n³ instead of n²"}, {"option_key": "D", "hint": "This is the inverse-square ratio (1/n²). The radius increases as n², not decreases. This ratio describes how energy varies with n.", "misconception": "Confusing the energy level formula (−13.6/n²) with the radius formula (n²a₀)"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The wavelength of the first line of the Balmer series of hydrogen is 656.3 nm. The wavelength of the second line of the Balmer series is approximately:", "explanation": "For the Balmer series, n₁ = 2. The first line: 1/λ₁ = R(1/4 − 1/9) = R(5/36). The second line: 1/λ₂ = R(1/4 − 1/16) = R(3/16). Therefore λ₂/λ₁ = (5/36)/(3/16) = (5 × 16)/(36 × 3) = 80/108 = 20/27. So λ₂ = 656.3 × (20/27) ≈ 486.1 nm.", "correct_answer": "A", "concept_tags": ["balmer-series", "rydberg-formula", "wavelength-calculation"], "payload": {"question_id": "cuet-phy-atom-bohr-07", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "486.1 nm", "is_correct": true}, {"key": "B", "text": "434.0 nm", "is_correct": false}, {"key": "C", "text": "364.6 nm", "is_correct": false}, {"key": "D", "text": "410.2 nm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "434.0 nm corresponds to the third Balmer line (n = 5 to n = 2), not the second line.", "misconception": "Selecting the wrong line of the series"}, {"option_key": "C", "hint": "364.6 nm is close to the series limit of the Balmer series (n = ∞ to n = 2), not the second line.", "misconception": "Confusing a specific line with the series limit"}, {"option_key": "D", "hint": "410.2 nm corresponds to the fourth Balmer line (n = 6 to n = 2), not the second line.", "misconception": "Selecting the wrong line of the series"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ionization energy of the hydrogen atom in the ground state is 13.6 eV. The energy required to ionize a hydrogen atom from its first excited state is:", "explanation": "The first excited state corresponds to n = 2. The energy of this state is E₂ = −13.6/2² = −13.6/4 = −3.4 eV. Ionization means removing the electron to E = 0 (n = ∞). Therefore, the ionization energy from the first excited state = 0 − (−3.4) = 3.4 eV.", "correct_answer": "C", "concept_tags": ["ionization-energy", "excited-state", "energy-levels"], "payload": {"question_id": "cuet-phy-atom-bohr-08", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "13.6 eV", "is_correct": false}, {"key": "B", "text": "6.8 eV", "is_correct": false}, {"key": "C", "text": "3.4 eV", "is_correct": true}, {"key": "D", "text": "1.51 eV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "13.6 eV is the ionization energy from the ground state (n = 1), not from the first excited state (n = 2).", "misconception": "Using ground state instead of first excited state"}, {"option_key": "B", "hint": "6.8 eV = 13.6/2, which incorrectly divides by n instead of n². The energy varies as 1/n².", "misconception": "Dividing ionization energy by n instead of n²"}, {"option_key": "D", "hint": "1.51 eV = 13.6/9 corresponds to the energy of the n = 3 level. The first excited state is n = 2, not n = 3.", "misconception": "Confusing second excited state (n = 3) with first excited state (n = 2)"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The speed of an electron in the first Bohr orbit of hydrogen atom is v₁. The speed of the electron in the third orbit will be:", "explanation": "The speed of an electron in the nth Bohr orbit is given by vₙ = v₁Z/n. For hydrogen (Z = 1) in the third orbit (n = 3): v₃ = v₁/3. The electron speed decreases as 1/n because for larger orbits, the Coulomb force is weaker and the electron moves more slowly.", "correct_answer": "D", "concept_tags": ["orbital-velocity", "bohr-model", "velocity-quantization"], "payload": {"question_id": "cuet-phy-atom-bohr-09", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "3v₁", "is_correct": false}, {"key": "B", "text": "v₁/9", "is_correct": false}, {"key": "C", "text": "9v₁", "is_correct": false}, {"key": "D", "text": "v₁/3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This suggests speed increases with n, but in Bohr''s model, the electron moves slower in higher orbits. Speed is inversely proportional to n.", "misconception": "Assuming speed increases with orbit number"}, {"option_key": "B", "hint": "v₁/9 = v₁/3² implies speed varies as 1/n². However, speed varies as 1/n, not 1/n².", "misconception": "Confusing 1/n dependence of velocity with 1/n² dependence of energy"}, {"option_key": "C", "hint": "This would mean the speed increases as n², which contradicts Bohr''s model where higher orbits have lower speeds.", "misconception": "Confusing velocity with radius formula"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The total number of spectral lines emitted when a hydrogen atom de-excites from the nth energy level to the ground state is given by n(n−1)/2. If a sample of hydrogen atoms is excited to the 4th energy level, how many spectral lines can be observed?", "explanation": "When hydrogen atoms are excited to the 4th energy level (n = 4), they can de-excite through various transitions. The total number of spectral lines = n(n−1)/2 = 4(4−1)/2 = 4 × 3/2 = 6. These lines correspond to transitions: 4→3, 4→2, 4→1, 3→2, 3→1, and 2→1.", "correct_answer": "B", "concept_tags": ["spectral-lines", "energy-transitions", "hydrogen-spectrum"], "payload": {"question_id": "cuet-phy-atom-bohr-10", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "4", "is_correct": false}, {"key": "B", "text": "6", "is_correct": true}, {"key": "C", "text": "10", "is_correct": false}, {"key": "D", "text": "3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This might come from thinking only about transitions from n = 4 directly to lower levels (4→3, 4→2, 4→1), but that gives only 3 lines from level 4. You must also count transitions between intermediate levels.", "misconception": "Counting only transitions originating from the highest level"}, {"option_key": "C", "hint": "10 = 5(5−1)/2, which would be the answer for n = 5, not n = 4.", "misconception": "Using the wrong value of n in the formula"}, {"option_key": "D", "hint": "3 counts only the direct transitions from n = 4 (to n = 3, 2, and 1), ignoring transitions like 3→2, 3→1, and 2→1.", "misconception": "Counting only transitions from the highest level to each lower level"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The radius of the innermost orbit of a hydrogen atom is 0.53 Å. The radius of the third orbit of He⁺ ion is:", "explanation": "The radius of the nth orbit for a hydrogen-like atom is rₙ = n²a₀/Z. For He⁺ ion (Z = 2) in the third orbit (n = 3): r₃ = 3² × 0.53/2 = 9 × 0.53/2 = 4.77/2 = 2.385 Å ≈ 2.38 Å. The radius increases as n² but decreases as 1/Z.", "correct_answer": "D", "concept_tags": ["hydrogen-like-atom", "orbit-radius", "helium-ion"], "payload": {"question_id": "cuet-phy-atom-bohr-11", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "4.77 Å", "is_correct": false}, {"key": "B", "text": "0.265 Å", "is_correct": false}, {"key": "C", "text": "1.06 Å", "is_correct": false}, {"key": "D", "text": "2.38 Å", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4.77 Å = 9 × 0.53 Å is the radius of the third orbit of hydrogen (Z = 1). For He⁺, you must also divide by Z = 2.", "misconception": "Forgetting to account for Z in the radius formula for hydrogen-like ions"}, {"option_key": "B", "hint": "0.265 Å = 0.53/2 is the first Bohr orbit radius of He⁺. This does not account for n = 3.", "misconception": "Using n = 1 instead of n = 3"}, {"option_key": "C", "hint": "1.06 Å = 2 × 0.53 Å. This might result from using n = 2 for hydrogen or an incorrect formula.", "misconception": "Arithmetic error or using wrong quantum number"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following transitions in a hydrogen atom produces a photon of the shortest wavelength?", "explanation": "Shorter wavelength means higher energy of the emitted photon. The energy of a photon emitted during a transition is ΔE = 13.6(1/n₁² − 1/n₂²) eV. The transition n = 2 to n = 1 gives ΔE = 13.6(1 − 1/4) = 13.6 × 3/4 = 10.2 eV. The transition n = 5 to n = 4 gives ΔE = 13.6(1/16 − 1/25) = 13.6 × 9/400 = 0.306 eV. The transition n = 6 to n = 5 gives ΔE = 13.6(1/25 − 1/36) = 13.6 × 11/900 = 0.166 eV. The transition n = 3 to n = 2 gives ΔE = 13.6(1/4 − 1/9) = 13.6 × 5/36 = 1.89 eV. The largest energy difference (10.2 eV) corresponds to n = 2 → n = 1, giving the shortest wavelength.", "correct_answer": "A", "concept_tags": ["energy-transition", "photon-wavelength", "lyman-series"], "payload": {"question_id": "cuet-phy-atom-bohr-12", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "analyze", "options": [{"key": "A", "text": "n = 2 to n = 1", "is_correct": true}, {"key": "B", "text": "n = 5 to n = 4", "is_correct": false}, {"key": "C", "text": "n = 6 to n = 5", "is_correct": false}, {"key": "D", "text": "n = 3 to n = 2", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Transitions between high-n levels involve very small energy differences because energy levels get closer together at higher n. This gives a long wavelength.", "misconception": "Thinking higher quantum numbers give shorter wavelengths"}, {"option_key": "C", "hint": "The transition n = 6 to n = 5 involves the smallest energy gap among all the options, producing the longest wavelength photon.", "misconception": "Confusing longest and shortest wavelength"}, {"option_key": "D", "hint": "While this transition (first Balmer line) has a significant energy gap, it is much smaller than the n = 2 to n = 1 transition (10.2 eV vs 1.89 eV).", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The Bohr model successfully explains the spectra of hydrogen and hydrogen-like atoms but fails for multi-electron atoms.\nReason (R): The Bohr model does not account for electron-electron interactions and treats the problem as a single-electron system.", "explanation": "The Assertion is correct — the Bohr model works well for single-electron systems (H, He⁺, Li²⁺, etc.) but fails for multi-electron atoms like helium. The Reason is also correct and correctly explains why: the Bohr model considers only the Coulomb interaction between the nucleus and one electron, ignoring electron-electron repulsion. In multi-electron atoms, inter-electronic repulsion significantly affects energy levels, and the Bohr model has no provision for this. Hence both A and R are correct, and R is the correct explanation of A.", "correct_answer": "A", "concept_tags": ["bohr-model-limitations", "multi-electron-atoms", "electron-interaction"], "payload": {"question_id": "cuet-phy-atom-bohr-13", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly addresses why the Bohr model fails for multi-electron atoms — it ignores electron-electron interactions. This is the actual cause, making R the correct explanation of A.", "misconception": "Failing to see the causal link between electron-electron interaction and the model''s failure for multi-electron atoms"}, {"option_key": "C", "hint": "The Reason is factually correct. The Bohr model indeed treats only one electron interacting with the nucleus and has no mechanism for electron-electron repulsion.", "misconception": "Incorrectly believing the Bohr model accounts for electron-electron interactions"}, {"option_key": "D", "hint": "The Assertion is a well-established fact. The Bohr model accurately predicts spectra of H, He⁺, Li²⁺ but not of He, Li, etc.", "misconception": "Incorrectly thinking the Bohr model works for all atoms"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): In the Bohr model, the electron in a hydrogen atom does not radiate energy while revolving in a stationary orbit, even though it is an accelerating charge.\nReason (R): According to classical electromagnetic theory, an accelerating charged particle always radiates energy.", "explanation": "The Assertion is correct — Bohr''s second postulate explicitly states that electrons in stationary orbits do not radiate energy despite undergoing centripetal acceleration. This was a revolutionary departure from classical theory. The Reason is also correct — classical electromagnetic theory (Larmor formula) does predict that accelerating charges radiate energy. However, the Reason actually contradicts (or at least does not explain) the Assertion. Bohr''s postulate was introduced precisely to override this classical prediction. The Reason explains why the Bohr model had to introduce this postulate, but it does not explain why the electron does not radiate — it merely states the classical expectation. Both statements are true but R does not correctly explain A; rather, A is a postulate that overrides the classical prediction in R.", "correct_answer": "B", "concept_tags": ["bohr-postulates", "stationary-orbits", "classical-electrodynamics", "accelerating-charge"], "payload": {"question_id": "cuet-phy-atom-bohr-14", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R states the classical prediction that accelerating charges radiate, but A says the electron does NOT radiate. R describes what classical theory predicts (radiation), which is opposite to what A claims (no radiation). R cannot be the explanation of A.", "misconception": "Assuming R explains A when R actually describes the classical expectation that Bohr''s postulate overrides"}, {"option_key": "C", "hint": "The Reason is factually correct. Classical electromagnetic theory does predict that accelerating charges radiate energy (Larmor formula). This is a well-established result.", "misconception": "Confusing the Bohr postulate with classical electromagnetic theory"}, {"option_key": "D", "hint": "The Assertion is correct. It is a direct statement of Bohr''s second postulate about stationary orbits.", "misconception": "Thinking Bohr''s postulate is incorrect"}]}}]'::jsonb, 'deploy-2026-03-05-b09');

